INSERT INTO `autoren` (`aut_id`, `vorname`, `nachname`, `text`) VALUES
(0, 'Jean', 'Brune', 'Jean Brune est né le 12 mars 1912 à Aïn-Bessem. Miné par la perte de son Algérie pour laquelle il s’était tant battu et avait tant espéré un destin fraternel, Jean Brune est décédé à Nouméa, le 23 septembre 1973, à peine 5 semaines avant la fondation du Cercle algérianiste, le 1er novembre 1973.\nEn 1983, son biographe Francine Dessaigne a tenté de \"fixer cet être divers, artiste au crayon léger, maître des mots porteurs d’idées fortes, homme riche de cœur\" dans Jean Brune, Français d\'Algérie, ouvrage réédité en 1998 et augmenté  de ses croquis de guerre pris sur le vif quand, dans un char de la Première Division blindée, il avait débarqué sur les côtes de Provence, le 15 août 1944, avec tous les autres Français d’Algérie qui, d’un seul élan, venaient \"participer aux pompes bouleversantes de la bataille de la Libération\".\nÀ partir de 1945, Jean Brune travaillait comme journaliste pour plusieurs journaux dont La Dépêche quotidienne. Ses deux romans Cette haine qui ressemble à l\'amour (1961) et La Révolte (1965) tout comme son pamphlet Interdit aux chiens et aux Français (1967) comptent parmi les classiques de la littérature pied-noir.'),
(1, 'Jean', 'Pélégri', ' '),
(2, 'Wolf', 'Albes', ' '),
(3, 'Michèle', 'Piris-Lambert', ' '),
(4, 'Nicolas', 'Kayanakis', ' '),
(5, 'Fernand', 'Destaing', ' '),
(6, 'Louis', 'Pozzo di Borgo', ' '),
(7, 'Jeanine', 'de la Hogue', ' '),
(8, 'Andrée', 'Montero', ' '),
(9, 'Henry', 'Guey', 'J\'ai vu le jour à Alger, en septembre 1943. Mes parents, mon frère aîné et moi, habitions une petite villa dans la banlieue d\'Alger, à La Redoute. À l\'âge de 10 ans, nous déménagerons pour un modeste appartement proche du centre-ville. Je poursuivrai mes études secondaires à partir de la classe de 3<sup>e</sup> à l\'École de l\'air du cap Matifou, ou je serai admis, à la suite d\'un concours d\'entrée, en 1959. Je ferai partie de la promotion 1959-1963… que je ne terminerai pas à cause de l\'indépendance. À partir des vacances de Pâques 1962, nous ne retournerons plus à l\'école. La violence va se déchaîner : enlèvements et disparitions de civils organisés par le FLN, exactions commises par les CRS et gendarmes mobiles sur la population pied-noir. Je vivrai sur place de nombreux événements dramatiques, dont le plus traumatisant restera le 26 mars 1962 que je vivrai de très près avec mon père...\r\n\r\nLe <em>Ville de Tunis</em> nous expatriera… le 15 juin 1962, ma mère et moi, une tante et ses deux enfants, ainsi qu\'un frère de cette tante. Mon père arrivera à son tour, au mois de septembre 1962, pour une mutation à Béthune dans le Pas de Calais. Après une année de terminale à Toulouse, je commencerai une licence de physique-chimie à la faculté des sciences de Lille, licence que je terminerai à Toulouse, après ma rencontre avec celle qui deviendra mon épouse. Après 13 mois de service militaire, à la base aérienne de Toulouse-Francazal, je commencerai, en octobre 1970, une carrière d\'informaticien à la SNCF à Paris. Six ans plus tard, je « fuirai » la grisaille parisienne pour m\'installer à Aix-en-Provence, toujours en qualité d\'informaticien, mais dans le secteur bancaire cette fois.\r\n\r\nObsédé par mon vécu « algérois », la perte de ma terre natale, la perte d\'amis morts ou éparpillés à travers le monde après cette « débâcle », je griffonnais régulièrement quelques souvenirs sur un modeste journal, une forme de psychothérapie, avec l\'espoir de laisser à mon fils une trace de mon histoire.\r\n\r\nSur les encouragements d\'un ami, ces quelques notes et souvenirs, je les mettrai en forme plus lisible pour que d\'éventuels lecteurs comprennent mieux notre histoire.\r\n\r\nAvec l\'âge et le temps qui passe, et même si ma mémoire commence doucement à me faire défaut, ces 19 premières années de ma vie restent et resteront profondément gravées en moi jusqu\'à la fin de mes jours. Ce sont elles qui ont fait ce que je suis devenu aujourd\'hui.\r\n\r\nPréretraité à partir de 2004, retraité définitif en 2006, j\'ai repris à plein temps une activité que  je pratiquais à « temps partiel » depuis la fin des années 80 : la peinture. J\'ai retrouvé en Provence une partie des couleurs et lumières de ma terre natale et grâce à cette activité, j\'ai trouvé une forme de sérénité, face à une époque et un pays n\'existant plus que dans ma mémoire.\r\n\r\n<strong>http://henri.guey.free.fr/</strong>'),
(10, 'Maurice', 'Calmein', 'Maurice Calmein est né en 1947 à Oran. \nEn 1960, sa famille s’installe à Toulouse où, dès l’âge de vingt ans, il milite dans des associations de Français d’Algérie. Président de l’Amicale universitaire pied-noir, il rencontre Jean Pomier, l\'un des fondateurs du mouvement algérianiste, dont il devient l’ami malgré leurs soixante ans d’écart. Il fondera lui-même le Cercle algérianiste quelques années plus tard et Jean Pomier en sera le président d’honneur. \nMaurice Calmein est l’auteur de plusieurs livres sur l’Algérie, dont Exode, Les Français d\'Algérie. 1962-2014, Dis, c\'était comment à l\'époque de l\'Algérie française ? et le roman Le Sel des Andalouses. \nIl a assuré l’éditorial de la revue l’Algérianiste pendant plus de dix ans.'),
(11, 'Suzon', 'Pulicani-Varnier', ' '),
(12, 'Jocelyne', 'Mas', ' '),
(13, 'Hélie', 'de Saint Marc', ' '),
(14, 'Olivier', 'Podevins', ' '),
(15, 'Le', 'Livre interdit', ' '),
(16, 'Anne-Marie', 'Lorentz', ' '),
(17, 'Marie-Louise', 'de Pena', ' '),
(18, 'Christiane', 'Lacoste-Adrover', ' '),
(19, 'Jean-Pierre', 'Lledo', 'Jean-Pierre Lledo est né en 1947 à Tlemcen. Algérien depuis le 6e siècle avant l’ère commune, par ses ancêtres maternels juifs, et depuis 1848, par les paternels catalans.\r\nÀ la suite de menaces islamistes, Jean-Pierre Lledo a dû quitter l\'Algérie en 1993. Depuis, il a réalisé plusieurs films documentaires liés aux réalités multiethniques de l\'Algérie d\'avant 1962, mémoires refoulées par l\'histoire officielle.\r\n\r\nJean-Pierre Lledo vit aujourd\'hui en Israël.'),
(20, 'Janine', 'Montupet', 'Janine Montupet, par toutes ses fibres, appartient à la  terre d’Algérie. Ses ancêtres s’y sont installés dès 1848. \nAu travers de cette grande fresque romanesque que constitue la trilogie La Fontaine rouge (1953-1955) Janine Montupet a imaginé de nous décrire les propriétaires successifs du domaine de la Fontaine rouge située dans la plaine de la Mitidja. \nLa Traversée de Fiora Valencourt  clot cette grande saga algérienne.'),
(21, 'Francine', 'Dessaigne', ' '),
(22, '', 'autocollant', ''),
(23, 'Henri', 'Mazzarino', 'À partir d’octobre 1960, le sous-officier de l\'Armée de l\'Air Henri Mazzarino organise la résistance à Blida. Quelques mois plus tard, « Mazza » rejoint l’OAS avec son groupe. En octobre 1961, il déserte et passe dans la clandestinité. Blida sera la \"seule ville où l’OAS prend un caractère représentatif\" (Pierre Montagnon, La Guerre d’Algérie).'),
(24, 'Monique', 'Clavaud', ' '),
(25, 'André', 'Laroche', ' '),
(26, 'Nicole', 'Guiraud', 'Nicole Guiraud est née en 1946 dans le Sahel algérois, descendante d’une lignée de pionniers enracinés dans le pays depuis cinq générations. À 10 ans, elle est grièvement blessée dans l’attentat du Milk Bar, le 30 septembre 1956 à Alger. \nDans son Journal, elle retrace les violences de la guerre civile entre avril et juin 1962 à Alger qui mènera à l’exode des Français d’Algérie. \nArtiste plasticienne, elle témoigne de la mémoire oubliée d’une Algérie plurielle, avec ses moments de bonheur intense et ses déchirements cruels.'),
(27, '', 'Documents', ' '),
(28, 'Michel de ', 'Laparre', ''),
(29, 'Charles', 'Galléa', ' '),
(30, 'Maïa', 'Alonso', 'Maïa Alonso est l’enfant de la quatrième génération d’une famille espagnole arrivée d’Arboleas pendant l’été 1870, pour s’établir dans le Sud oranais, dans la région de Mascara.\nElle vit en Gascogne après une jeunesse nomade entre Toulouse, Londres et Paris. Elle a publié trois romans : L’odyssée de Grain de Bled en terre d’Ifriqiya (L’Harmattan, 2013) ; Le soleil colonial – Au royaume des cailloux (Atlantis, 2014 ; Prix Terre d’Eghriss 2014) et Les Enfants de la Licorne (Atlantis, 2015).'),
(31, 'Jérôme', 'Tanon', 'Jérôme Tanon est né en 1935 à Paris. \nIl a vécu au Maroc, puis à Alger, jusqu’à l’âge de 19 ans. Après une longue carrière d’ingénieur dans l’industrie, il s’est installé dans le Midi. \n« Toi, tu es un Français de France », me disaient mes camarades, tant musulmans que français d’Algérie, alors que j’avais passé toute ma jeunesse parmi eux. \nIl a fallu plus de cinquante ans pour que je ressente le besoin d’exorciser cette singularité en une saga mêlant réalité et fiction, dans la vision d’un enfant au regard candide, puis naïf, enfin ingénu.'),
(32, 'Benoît', 'Gaumer', 'Benoît Gaumer a exercé et enseigné la médecine de santé publique successivement en Tunisie, en France mais aussi en Algérie et au Québec. \r\nTout comme Fernand Destaing, c’est un passionné de l’histoire de la médecine et un grand amoureux du Maghreb. \r\n'),
(33, 'Max', 'Teste', 'Max Teste est né le 9 juillet 1941 à Constantine, d\'un père ardéchois, arrivé très jeune en Algérie, et d\'une mère pied-noir, d\'origine maltaise. Peu après, ses parents, qui exploitaient une petite ferme près du Kroubs, s\'installèrent d\'abord à Alger, puis dans un petit village de la Mitidja.\r\n\r\nIl fit ses études secondaires au lycée Duveyrier de Blida, puis com­mença ses études supérieures à l\'université d\'Alger.\r\n\r\nAtteint, comme beaucoup de Pieds-Noirs, dès son arrivée en France, d\'une \"nostalgérite\" incurable, il milita dans de nombreu­ses associations et amicales de rapatriés.'),
(34, 'Marc', 'Faber', 'Marc Faber lebt und arbeitet seit über 20 Jahren in der Provence, am Fuße des Mont Ventoux.'),
(35, 'Danielle', 'Deliot-Libmann', ''),
(36, 'Herbert', 'Wittmann', ''),
(37, 'Roger', 'Vétillard', 'Roger Vétillard est historien, auteur de plusieurs ouvrages sur les conflits et les insurrections algérien­nes, dont <em>Sétif, Guelma 1945. Massacres en Algérie (</em>2011) et <em>20 août 1955 dans le Nord-Constantinois. Un tournant dans la guerre d\'Algérie ? (</em>2013).'),
(38, 'Eva', 'Albes', ''),
(39, 'Peter Alfred', 'Bletschacher', ''),
(40, 'Erwin', 'Münsch', ''),
(41, 'Jean', 'Taousson', ''),
(42, 'Charles', 'Courtin', ''),
(43, 'Josef', 'Mair', ''),
(44, 'Daniel', 'Pouilly', ''),
(45, 'Philippe', 'Lamarque', ''),
(46, 'Danilo', 'Pagliaro', ''),
(47, 'Hafida', 'Chabi', ''),
(48, 'Béatrice', 'Riquelme-Olivieri', '<strong>Béatrice Riquelme-Olivieri </strong>est née au Maroc en 1956 et vit à Paris depuis 1975.\r\n\r\nElle a toujours gardé des atta­ches pro­fondes avec ce pays, où vit encore une partie de sa famille.\r\n\r\nLors de ses recherches généalogi­ques, elle a découvert l\'histoire fami­liale mou­vemen­tée des Riquelme.'),
(49, 'Roger', 'Vétillard', '');
