INSERT INTO `publikationen` (`pub_id`, `kat_id`, `aut_id`, `titel`, `text`, `preis`, `isbn`, `available`) VALUES
(0, 1, 0, 'Les Mutins', '<b>Le mutin Don Saturnino et l’abandon des Harkis</b>\r\nEn 1898, la garnison espagnole de Baler aux Philippines (île de Luzón) résiste héroïquement à l’assaut des troupes du révolutionnaire Villacorta. Lorsque l’état-major espagnol décide d’abandonner la colonie, le jeune lieutenant Don Saturnino refuse de se replier au nom de l’honneur et de la patrie. Le colonel Don Cristóbal tente de le rappeler à l’ordre. Mais Don Saturnino, sûr d’avoir raison, refuse tout compromis qui ne serait que compromission. II n’est pas prêt à livrer ses camarades philippins, ces « Harkis » avant la lettre, à l’ennemi.\r\n\r\n<b>Le putsch d’Alger en 1961</b>\r\nLa transposition saute aux yeux : le drame de Don Saturnino et de ses camarades aux Philippines c’est celui que vécurent tant d’officiers français en Algérie face à la politique de l’abandon du général De Gaulle. En avril 1961, le putsch des généraux Challe, Jouhaud, Zeller et Salan échoue. S’ensuivent la recrudescence du terrorisme, une guerre civile impitoyable, les honteux accords d’Evian, la fusillade de la rue d’Isly, le calvaire des Français d’Algérie, le massacre de dizaines de milliers d’anciens harkis...\r\n\r\n<b>Le drame de l’Armée française en Algérie</b>\r\nAprès <i>Cette haine qui ressemble à l’amour</i>, grande fresque romanesque sur la guerre d’Algérie publiée en 1961, Jean Brune choisit, en 1967, le genre dramatique pour illustrer le déchirement atroce de l’Armée française devant les décisions inattendues du pouvoir politique et de l’Etat-major. Dans les <i>Mutins</i>, il est question d’honneur et de devoir, de rêve et d’idéalisme dans cet ordre laïc que représente l’Armée. Et surtout d’un amour sincère qui n’a pas peur du pathétique : Don Saturnino, ce moine-soldat, éprouve une égale tendresse pour l’Espagne, pour son épouse Isabelle et pour ses frères d’armes, espagnols et philippins.\r\n\r\n<b>Une pièce inachevée</b>\r\nLe manuscrit de Jean Brune s’arrête au milieu du dernier acte lorsque Don Saturnino est traduit devant le Tribunal Militaire. C’est la tête haute qu’il se présente devant ses \"juges\". qu’il assume sa responsabilité et qu’il entame sa défense avec l’appui du Padre Gómez Carreño.\r\nLibre donc au lecteur de peser les arguments, de juger par lui-même, et de choisir sa propre fin...', 10, '978-3-932711-01-5', 1),
(1, 1, 0, 'La guerre de Troie commence demain', 'Ce titre claque déjà comme les ironiques prémices d’une joute lancée contre Jean Giraudoux. Tragi-comédie ou pochade, peut se demander le lecteur selon qu’il incline vers le sérieux, aéré d’un clin d’œil, ou vers la légèreté d’écriture. Brune a choisi « divertissement ».\r\n<table border=\"0\">\r\n<tbody>\r\n<tr>\r\n<td>Agamemnon:</td>\r\n<td>Nous souhaitons savoir si Paris t’a enlevée, Hélène.</td>\r\n</tr>\r\n<tr>\r\n<td>Hélène:</td>\r\n<td>Il m’était difficile de partir seule, à la nage, jusqu’à la côte d’Asie.</td>\r\n</tr>\r\n<tr>\r\n<td>Agamemnon:</td>\r\n<td>Certes !... Mais Paris t’a-t-il emmenée de vive force, après une courte lutte et malgré tes protestations, tes cris ? N’as-tu pas appelé Ménélas au secours ?</td>\r\n</tr>\r\n<tr>\r\n<td>Hélène:</td>\r\n<td>Non. J’ai préféré ne pas le déranger.</td>\r\n</tr>\r\n<tr>\r\n<td>Agamemnon:</td>\r\n<td>Une femme qu’on enlève ne dérange pas son mari si elle l’appelle.</td>\r\n</tr>\r\n<tr>\r\n<td>Hélène:</td>\r\n<td>Les amoureux n’ont pas besoin qu’on les alerte pour deviner qu’une fille les quitte, Agamemnon. II n’en est pas toujours de même des maris. Ils sont volontiers distraits. Ils ne s’aperçoivent jamais du départ de leur épouse et ne l’apprennent en général que de la rumeur populaire quand elle devient assourdissante.</td>\r\n</tr>\r\n<tr>\r\n<td>Agamemnon:</td>\r\n<td>Ainsi Ménélas n’a rien vu ?</td>\r\n</tr>\r\n<tr>\r\n<td>Hélène:</td>\r\n<td>Non ! Il guettait le rayon vert.</td>\r\n</tr>\r\n<tr>\r\n<td>Agamemnon:</td>\r\n<td>Et tu affirmes que Paris ne t’a pas fait violence. Il n’a pas déchiré tes vêtements, par exemple ?</td>\r\n</tr>\r\n<tr>\r\n<td>Hélène:</td>\r\n<td>Non ! J’étais nue.</td>\r\n</tr>\r\n</tbody>\r\n</table>', 9.9, '978-3-932711-02-2', 1),
(2, 1, 0, 'Alger – Bab-el-Oued', 'Après les deux pièces de théâtre <i>Les Mutins</i> et <i>La guerre de Troie commence demain</i>, l’essai <i>Alger – Bab-el-Oued</i> (1956) est une nouvelle révélation parmi les œuvres inédites de Jean Brune.\r\nPartout on y respire ce «parfum plus secret» dont parle Albert Camus dans <i>L’Eté à  Alger</i>. Si Camus a chanté Belcourt, Brune s’est penché sur le quartier de Cagayous, Bab-el-Oued.\r\nC’est plein de tendresse et d’humour que Jean Brune peint la vie de Bab-el-Oued pendant plusieurs décennies. Il dévoile les secrets de maints endroits et, bien entendu, des habitants de ce <i>melting pot</i> à  la fois fascinant et amusant…\r\nDans cette nouvelle édition, des extraits du <i>Journal d’exil</i> complètent les écrits de Jean Brune sur Bal-el-Oued qu’il considérait comme sa «patrie selon le cœur» bien qu’il n’y soit pas né.', 7.6, '978-3-932711-03-9', 1),
(3, 1, 0, 'Cette haine qui ressemble à  l’amour', 'À une phase décisive de la guerre d’Algérie, le \"Colonel\" est à la poursuite du rebelle insaisissable Kim ben Kim dont la cruauté et la violence risquent de faire basculer la population musulmane du côté des terroristes FLN et les colons dans le contre-terrorisme.\r\nPourtant, le souci majeur du colonel c’est de conserver intact le \"capital amour\" qui permettra, une fois la victoire militaire acquise, de préparer la réconciliation des deux camps.\r\n\r\nMais comment vaincre et à quel prix ?\r\n\r\nNi plaidoyer, ni réquisitoire, <i>Cette haine qui ressemble à l’amour</i> est, avant tout, une grande fresque romanesque où le lecteur se trouve projeté dans les deux camps d’une aventure guerrière et révolutionnaire. Une foule de personnages, des décors vrais, une hauteur de vue et une tendresse profonde pour des héros qui luttent contre tout espoir font de ce roman l’<i>Autant en emporte le vent</i> de la guerre d’Algérie écrit par Jean Brune dont la connaissance de la terre d’Afrique est sans défaut.\r\n\r\nLa réédition intégrale de <i>Cette haine qui ressemble à l’amour</i>, roman paru pour la première fois en 1961 aux Editions de la Table Ronde, permet de mieux comprendre l’énorme complexité du drame algérien – celui des années 1954 à 1962, mais également celui de la terrible guerre civile à partir de 1990…', 36, '978-3-932711-04-6', 1),
(4, 1, 0, 'Interdit aux chiens et aux Français', 'C’est tout le drame de l’Algérie française qui surgit dans ce chef-d’œuvre de Jean Brune : les débuts des «événements», la stratégie terroriste du F.L.N., la bataille d’Alger, l’espoir des fraternisations de mai 1958, la victoire militaire sur le terrain, la trahison du général de Gaulle, le putsch des généraux, l’imposture des accords d’Evian.\r\n\r\nSuivent la dramatique agonie de l’Algérie française, le massacre des Harkis, le calvaire des Pieds-Noirs, la résistance des officiers « rebelles » et leur douloureux passage à  la clandestinité.\r\n\r\nUne place de choix est réservée aux expériences délirantes de «Georges Untel», colon de bonne volonté, resté dans sa ferme dans l’Algérie algérienne…\r\nDes réflexions qui sonnent juste dans cet extraordinaire pamphlet plein de verve, d’humour, de colères, de lyrisme et de larmes.Nouvelle édition revue et corrigée de 2008.', 18.5, '978-3-932711-05-3', 1),
(5, 1, 0, 'Aventures prodigieuses de Georges Untel en Algérie algérienne', 'Après l’indépendance de l’Algérie, tous les Pieds-Noirs ont quitté leur pays natal.\r\nTous à\r\nNon ! Quelques colons irréductibles dont Georges Untel, sont restés à  leur ferme. D’humeur candide et bienveillante, Georges Untel croit aux « garanties » insérées dans les accords négociés à  Evian, en faveur des Français résidant en Algérie. En plus, on leur a maintes fois assuré que tout était prévu pour que soient préservés leurs biens et leur vie, les domaines et la dignité...\r\n... à  la condition, bien entendu, qu’ils consentent à  s’intégrer dans l’ordre nouveau créé par l’indépendance de l’Algérie...\r\nGeorges Untel va bientôt découvrir que la vie n’est pas facile en « Algérie algérienne »...', 4.6, '978-3-932711-06-0', 1),
(6, 1, 0, 'Lettre à  un maudit', 'Après l’exode douloureux de 1962, c’est un émouvant appel à  la réconciliation que Jean Brune lance à  ses compatriotes pieds-noirs.\r\n\r\n<center>Quand tout s’effondre, \r\nles valeurs formelles n’ont plus cours.\r\nIl faut réinventer le devoir \r\net non pas nouer des intrigues dérisoires.\r\n\r\nFonde-toi orgueilleusement\r\net attends l’avenir, \r\nil naîtra naturellement de tes silences.\r\n\r\nL’avenir,\r\nce n’est que de la ferveur à  mettre en ordre.\r\nCe vide que tu découvres autour de toi,\r\nc’est la chance que t’offre le destin.\r\nVoici une France à  faire. \r\nTu étais germe en Afrique, \r\ntu seras germe en Europe.\r\n\r\nDans la mue générale du monde,\r\nce que tu feras avec les Français\r\npeut atteindre à  une telle dimension d’exemple \r\nque la France retrouvera ce rôle d’éclaireur\r\nqu’elle a dédaigné en Afrique.\r\n\r\nLe rêve recommence.\r\n\r\n(Jean Brune, 1963)</center>', 4.6, '978-3-932711-07-7', 1),
(7, 1, 0, 'Anthologie Jean Brune', 'Choisir dans l’œuvre de Jean Brune est une véritable gageure. Réunissant les meilleurs textes, croquis, tableaux et photos – dont beaucoup sont encore inédits – ce recueil permet de découvrir l’immense talent de ce grand écrivain, journaliste et peintre.\r\n\r\n<center>Soudain revivent :\r\nJean Brune – Algérien, Algérois\r\nJean Brune – ami d’Albert Camus\r\nLes écrivains – amis et ennemis\r\nCombat pour l’Algérie française\r\nL’humour de Jean Brune\r\nLa disparition de Jean Brune\r\nCroquis\r\nTableaux\r\nPhotos</center>', 17, '978-3-932711-08-4', 1),
(8, 1, 0, 'Journal d’exil', 'Dans son <i>Journal d’exil</i>, Jean Brune décrit son errance à travers l’Europe, de juillet 1961 jusqu’au février 1963. C’est un récit à la fois plein d’amertume et de tristesse, mais aussi de révolte et d’humour. Et, bien entendu, rayonnant de poésie.\r\n\r\n<strong>Là-bas</strong>\r\n\r\nLa beauté des ciels italiens\r\nme blesse comme une insolence ou un défi,\r\nparce qu’elle me ramène irrésistiblement\r\naux paysages perdus.\r\nLa magie de la lumière\r\nsur les plateaux pierreux,\r\nles colères des vagues sur les plages\r\net les nuages que le vent pétrit\r\nde formes rassurantes\r\ncomme des chimères familières,\r\ntout ce qui est\r\nlà -bas\r\nà la fois semblable et différent\r\nde ce que m’offrent ici\r\nles mêmes arbres, les mêmes rivages et\r\ndes ciels identiques, parce que\r\nlà -bas,\r\ntout est alourdi d’un grand secret\r\nqui est le souvenir des premiers émerveillements\r\nde l’enfance.', 13, '978-3-932711-09-1', 1),
(9, 1, 0, 'La Révolte', '<em>« Le mauvais coup que l’on prépare »</em>, disait Samar, <em>« c’est notre assassinat. On veut nous livrer. Et maintenant tout se noue dans l’un de ces silences qui, dit-on, précèdent les grandes fureurs.</em>\r\n<em> L’ennemi peut se taire. II est partout autour de cette ville où nous voici enfermés avec l’armée. Il sait qu’ici se jouera le sort. II attend. Sans doute ne parvient-il pas à croire que l’armée souscrira au plan diabolique. II sait que sa victoire, et la ruée et le pillage et le carnage ne dépendent ni de sa sauvagerie ni de sa fureur, mais de la décision que prendra l’armée.</em>\r\n<em> Et nous, nous savons que notre vie ou notre mort, ou notre exil, qui sera une autre forme de mort, dépendent aussi du même arrêt.</em>\r\n<em> Avec l’armée nous pouvons tout, parce que nous restons des citoyens. Sans elle, nous ne serons que des mutins.</em>\r\n<em> Mais nous assumerons notre destin de mutins. Nous nous battrons. Nous avons jeté les bases d’une Organisation clandestine. Ce n’est encore qu’une ébauche ; mais autour d’elle nous mobiliserons la ville. »</em>\r\n\r\nDans ce chef d\'oeuvre, Samar, cet alter ego de Jean Brune, vit la phase finale de la guerre d\'Algérie à Alger où l\'OAS, le FLN et l\'Armée française s\'affrontent dans une lutte sans merci.', 20, '978-3-932711-10-6', 1),
(10, 1, 1, 'Les Oliviers de la Justice', '<i>Quelqu’un a dit qu’il fallait rédiger un communiqué pour les journaux, et nous l’avons écrit sur le balcon, avec les mots d’usage. « ... Il faisait partie de ces colons de la première heure qui par leur travail ont fertilisé la Mitidja. Avec lui, c’est une des dernières figures de cette génération qui s’éteint... » Malgré la convention des mots, c’était vrai. Cela résumait bien sa vie.</i>\r\n\r\n<i>Les Oliviers de la Justice</i> (1959) sont un livre de tendresse et d’émotion, de colère parfois - mais surtout de reconnaissance, où sont peints les rapports réels – et souvent secrets et « souterrains » - entre Musulmans et Européens. Ainsi, à travers une expérience particulière, se dessine un tableau de l’âme et de la sensibilité algérienne.\r\n\r\nL’auteur a voulu faire chanter la vérité, celle des hommes – celle qui fait comprendre et aimer.\r\n\r\nC’est donc aussi, malgré tout, un livre d’espoir.\r\n\r\n<center>Avec une nouvelle préface de l’auteur\r\net plusieurs documents sur le film de James Blue et Jean Pélégri\r\n<i>Les Oliviers de la Justice</i> tourné en Algérie fin 1961 début 1962\r\nainsi que des photos du film et de la ferme des Pélégri (prises en avril 1990)</center>', 17, '978-3-932711-11-4', 1),
(11, 1, 2, 'Jean Brune et Albert Camus. Deux écrivains pieds-noirs face au drame de l’Algérie  française', 'Jean Brune (1912-1973) a été le condisciple d’Albert Camus (1913-1960) au lycée d’Alger et, comme il le dit <i>«au cours de la vie parfois son ami»</i>.\r\nÀ comparer les deux écrivains pieds-noirs prestigieux on découvre des ressemblances surprenantes entre <i>Cette haine qui ressemble à  l’amour</i> et <i>La Révolte</i> d’un côté, et <i>Noces, L’Été, L’Hôte</i> et <i>Le Premier Homme</i> de l’autre.\r\n\r\nFace au drame de l’Algérie française, leur réaction a été unanime : ils insistaient sur le <i>«droit des hommes à  ne pas être chassés de leurs souvenirs d’enfance»</i>.\r\n\r\nNouvelle édition revue et corrigée de 2010.', 14, '978-3-932711-12-1', 1),
(12, 1, 0, 'Bab-el-Oued raconté à  Toinet. Jean Brune, le journaliste (1)', 'Découvrez à  travers ce recueil d’articles pleins d’humour le petit peuple exubérant et coloré de Bab-el-Oued.\r\nJean Brune les a écrits en tant que journaliste à  <i>La Dépêche quotidienne</i> entre janvier et avril 1955.\r\nComme il les illustrés lui-même par d’innombrables et savoureux croquis – dont vous trouverez une cinquantaine dans ce recueil – ce petit livre précieux, témoignage de la tendresse de Jean Brune, est devenu un véritable document historique sur ce quartier d’Alger si original qui a disparu.\r\n\r\nAvec 54 croquis inédits de Jean Brune.', 11, '978-3-932711-13-8', 1),
(13, 1, 0, 'Algérie 1955. La bataille de la peur. Jean Brune, le journaliste (2)', 'Découvrez à travers ce recueil d’articles de Jean Brune les analyses lucides du début de la guerre d’Algérie écrites pour <i>La Dépêche quotidienne d’Algérie</i> entre mai et août 1955.\r\nJean Brune s’est rendu sur place pour enquêter sur les causes et l’étendue de la rébellion, discuter avec les militaires, écouter les angoisses des gens du bled, questionner des rebelles capturés.\r\nDe ce drame atroce, il esquisse les données politiques, économiques et surtout psychologiques, au plus près de la vérité. Bien sûr, Jean Brune nous parle en journaliste. Mais ses descriptions de l’Aurès, de Sétif, de Batna, du Sersou et de tant d’autres endroits n’en sont pas moins imprégnées de cette beauté poétique qu’on retrouvera plus tard dans <i>Cette haine qui ressemble à l’amour</i> (1961) et <i>La Révolte</i> (1965).\r\n\r\n<center>Table</center><b>\r\nLe premier objectif des fellaghas était de gagner la « bataille de la peur »\r\nL’Algérie en face de son destin</b>\r\nI. La gravité du drame algérien\r\nII. Les constantes du problème algérien\r\nIII. La solution des économistes\r\nIV. Aux sources du malaise français\r\nV. L’école, la route, les communes mixtes\r\n<b>Psychologie du terrorisme</b>\r\nDe Genève à Sétif\r\nLe communisme et les médersas libres\r\nLe Culte musulman et l’Etat français\r\nLes petits détails importants...\r\n\r\nAvec dix croquis inédits.', 12, '978-3-932711-14-5', 1),
(14, 1, 3, 'Acacia ou un Arbre sous la dune', '<i>« Drôle, hein ! qu’il m’ait fallu vingt ans pour me rendre compte que j’étais une fille d’Afrique, avec tout ce que cela comporte : l’amour des dunes, des pierres qui s’effritent, des fleurs qui résistent aux embruns et à  la sécheresse, de la mer enfin, qui a beau ressembler à  d’autres, est unique au monde… pour moi.\r\nCette sensation du corps et de l’âme à  la vue de son pays à  travers le hublot…\r\nCette impression de se retrouver dans son élément…\r\nCe gonflement du cœur devant tel paysage familier…\r\nCette larme débordante d’un trop plein de joie inexplicable…\r\nC’est le pays où je suis née !\r\nJe l’aime et à  ce moment seulement, je ressens le déchirement de mes aînés. »</i>\r\n\r\nEn bandoulière, des racines algériennes, niées, proches de l’asphyxie…\r\n… et un voyage « sanitaire pour récupérer « l’Arbre » qui préférerait mourir en terre faussement promise.\r\nUne jeune femme à  la rencontre de sa grand-mère et de sa propre identité perdue…\r\n… à  travers des personnages, des paysages, des odeurs, des souvenirs anecdotiques et émouvants.', 16, '978-3-932711-15-2', 1),
(15, 1, 4, 'Algérie 1960 : la victoire trahie. Guerre psychologique en Algérie', 'Au lendemain de la guerre d’Indochine, l’Armée française définit l’<i>Arme psychologique</i> pour riposter à la guerre révolutionnaire et la met en œuvre pour établir la paix en Algérie.\r\n\r\nLa victoire en Algérie supposait la participation des Musulmans dans les troupes de la France. Cette participation était un but de guerre et un moyen de la faire ; la guerre d’Algérie, guerre révolutionnaire visait autant la conquête d’une population que d’un territoire.\r\n\r\nLes buts de guerre officiellement fixes en 1957 – pérennité de la présence française, respect des communautés, personnalité algérienne – sont complétés en 1958 par l’égalité de tous les citoyens dans une seule France.\r\nOrganismes d’action psychologique, délégation des pouvoirs civils à l’Armée, <i>Sections administratives spécialisées</i> (S.A.S.) confiées à des officiers pour rétablir une administration locale – autant de moyens de pacification, autant d’occasions de conflits avec les pouvoirs civils. L’action sanitaire et sociale, la formation de la jeunesse, la réanimation de la vie municipale qui expriment une politique d’intégration et accompagnent reconquête militaire et opérations psychologiques conduisent à la constitution, en 1960 – 1962, d’une force armée musulmane française de 225.000 volontaires : 10 % de la population mâle adulte se bat contre le F.L.N. qui s’effondre.\r\n\r\nLes derniers chefs rebelles de l’Algérois proposent à l’Elysée une paix séparée qui aurait mis fin à la guerre dès l’été 1960. Mais De Gaulle préfère la négociation avec les chefs F.L.N. exilés à Tunis. C’est l’<i>Affaire Si Salah</i> maintenue secrète le temps nécessaire pour que la trahison s’accomplisse et pour en rendre les Français solidaires par leur vote aux référendums.\r\nBilan du génocide algérien :\r\n• neuf millions de citoyens dénationalisés ;\r\n• un million de concitoyens déportés ;\r\n• cent mille combattants livrés à l’ennemi par le Chef des Armées.', 22, '978-3-932711-16-9', 1),
(16, 1, 5, 'C’était l’Algérie heureuse (1915-1965)', '<i>Je veux d’abord parler du « Bled » algérien, mon berceau, la terre où j’ai grandi entre 1915 et 1935.\r\nMais je voudrais évoquer aussi ma vie d’homme jusqu’en 1965, dans Alger, Alger-la-Blanche qui demeure pour moi la plus belle ville du monde.\r\nAu total, j’aurai passé cinquante ans sur cette terre qui m’a vu naître. Un demi-siècle d’Algérie que je veux raconter pour laisser à mes enfants des racines profondes.\r\nCar ce sont les racines des hommes qui les empêchent d’être mortels. Nos souvenirs de jeunesse demeurent nos vraies richesses, notre plus bel héritage. Lorsqu’ils nous liront, « le soir a la chandelle », nos enfants ou les enfants de nos enfants diront peut-être en refermant ce livre : « C’était le temps de l’Algérie heureuse ».</i>\r\n\r\nAuteur de près de deux cents publications médicales, professeur de maladies infectieuses et tropicales à Alger, puis à Dijon, Fernand Destaing a développé dans cette dernière ville une seconde activité de <i>Médecine et Histoire</i> qui s’est soldée par la création d’un module, d’une trentaine de publications et d’une vingtaine de thèses.\r\n\r\nCet ouvrage sera réédité en juillet 2015.', 20.4, '978-3-932711-18-3', 1),
(18, 1, 15, 'Livre blanc. Alger, le 26 mars 1962 : la fusillade de la rue d’Isly', '80 morts, 200 blessés – c’est le bilan de la fusillade de la rue d’Isly, à Alger, le 26 mars 1962.\r\nLa deuxième réédition du <i>Livre interdit – Livre blanc</i> comprend les déclarations de 151 témoins de ces événements.\r\n\r\n<i>Et puis, avec la soudaineté d’un éclair, l’affreux drame a éclaté. Un tir extrêmement nourri nous arrosa, nous tous qui étions là . Je voyais sur le trottoir plusieurs soldats musulmans. Mais je n’en regardais qu’un. Chaque fois qu’un cri de douleur s’élevait de cette masse de corps allongés, ce soldat musulman, revêtu de l’uniforme français, en ricanant, en insultant, dirigeait vers l’endroit d’où semblait venir le cri de douleur, le tir de son pistolet-mitrailleur. La balle qui venait de frapper ma femme provenait-elle de son arme ?</i> (Alfred MESQUIDA, instituteur)\r\n\r\n<i>Tout à coup, sans aucune sommation ni provocation, les C.R.S. se sont mis à plat ventre en position de tir sous leurs véhicules, et un feu nourri a été dirigé vers la foule. Aux premières rafales deux femmes sont tombées. J’ai vu les C.R.S. qui continuaient à tirer sur ces gens sans répit.</i> (Luden PERRIN)\r\n\r\n<i>Quand tout fut terminé, je voulus voir. La France avait son Oradour et avait édifié dans le sang son mur de honte. Et j’ai eu honte pour la France. Je veux qu’on entende ma voix. Je veux que nos responsables sachent qu’il n’y a eu aucune provocation, aucun cri séditieux et que, tout au contraire, ce défilé s’amorçait dans le calme et la dignité. Je le jure sur l’honneur.</i> (Mme Albert MARGAILLAN)', 16, '978-3-932711-20-6', 1),
(19, 1, 6, '« Mon beau navire, ô ma mémoire... » Les paquebots de la malle d’Algérie (1830-1962)', 'Ecrire l’histoire des paquebots de la malle d’Algérie, c’est aussi écrire l’histoire de leurs passagers et, pour la majorité d’entre eux, du pays perdu.\r\nS’adapter ensemble aux évolutions parallèles de la science, du commerce, des mœurs, partager les mêmes événements de l’histoire, servir jusqu’aux limites extrêmes le même pavillon, tous ces défis ont fait battre à  l’unisson le cœur des hommes, les pistons des machines.\r\nEmbarquer à  leur bord, à  travers cet essai, remémore leur saga, tandis que se déroule en filigrane l’histoire de leur psychologie, telle qu’elle ressort de leurs conversations sur les ponts, traversée après traversée. Elle est le produit de leurs rêves, de leurs déceptions, de leurs doutes, de leurs peurs, de leurs préjugés, de leur orgueil, de leur coupable aveuglement devant un général qui se prenait pour le Richelieu d’une république couronnée alors qu’il n’était que son Badinguet.\r\n\r\nAvec une préface de Pierre Dimech.\r\n\r\nL’auteur, né le 12 décembre 1928 à  Oran, fonctionnaire des Finances à  la retraite, replié à  Montbéliard, a consacré une grande partie de son œuvre à  l’Algérie. Des poèmes, un essai (<i>L’Algérie d’hier et d’aujourd’hui</i>), deux romans (<i>La chanson d’amour qui toujours recommence</i> et <i>Le crucifix au-dessus du lit</i>), enfin un récit en pataouète, le jaléo, évoquent les joies, le travail, les colères de la communauté pied-noir.', 20, '978-3-932711-21-3', 1),
(20, 1, 7, 'Mémoire d’absence', 'Des lettres, comme un appel au secours, comme on jette une bouteille à  la mer, un bonheur enfui, un pays perdu et le refus de savoir la vérité. Le refuge dans le silence et la douleur s’entend plus encore.\r\n\r\nA côté de cette douleur, un inconnu, un témoin qui dit ce qu’il voit, ce qu’il croit comprendre.\r\nLettres et récit se répondent tout au long du livre et dessinent l’image d’un amour exceptionnel vécu dans un petit port de la côte algérienne. Un pays jamais nommé mais toujours présent comme, dans une tapisserie, la trame si essentielle.\r\nToujours présente aussi, la mer cruelle, si familière.\r\n\r\nJeanine de la Hogue, co-fondatrice de l’association <i>Mémoire d’Afrique du Nord</i>, dirige la revue <i>Mémoire plurielle</i>.\r\nNée en Algérie, elle est arrivée en France en 1962, a été journaliste, éditeur, écrivain. Spécialiste de la littérature française en Afrique du Nord, elle assure plusieurs chroniques de livres.', 17, '978-3-932711-22-0', 1),
(21, 1, 8, 'L’Autre Rivage', 'Andrée Montero est Oranaise. Son roman peut apparaître d’abord comme un témoignage sur la tragédie algérienne, le malheur des victimes du grand exode de l’été 1962.\r\nMais si l’auteur de <em>L’Autre Rivage</em> a su rendre perceptible le drame d’un déracinement et d’une torturante nostalgie, son mérite le plus sûr est ailleurs. Il est dans sa manière de montrer son héroïne égarée, perdue dans une terrible solitude, errant à travers les tentations, les obstacles et les ombres, prête souvent à fléchir et refusant chaque fois la défaite, Ariane qui résiste lucidement au Minotaure et trouve, à force de courage, de confiance dans le destin, la petite lueur qui mène enfin hors du labyrinthe.\r\nVoilà pourquoi également, le livre refermé, il s’en dégage, longtemps encore, cette « bouleversante odeur de vie » dont parle Camus, qui est l’odeur des villes comme des œuvres vivantes, celles où le cœur bat plus vite et où le sang bouillonne. (Emmanuel Roblès)\r\n\r\nNouvelle édition entièrement revue et corrigée.', 15, '978-3-932711-23-7', 1),
(22, 1, 9, 'A mon fils, à mon Algérie', 'Ces quelques lignes, je les écris avec mon cœur, avec ma passion pour une terre qui est la mienne et qui m’a été brutalement et injustement enlevée.\r\nJe les dédie à tous ceux qui comme moi ont « mal à l’Algérie », à tous les Pieds-Noirs connus et inconnus, à tous mes amis, à ceux qui nous ont quittés et que j’ai côtoyés pendant les dix-neuf premières années de ma vie.\r\nJe les dédie également à tous ces hommes et femmes qui ont contribué à la beauté de notre Algérie, à ceux qui ont lutté pour que ce pays reste terre française, qui ont perdu, ont été condamnés et sont morts pour raison d’État.\r\nElles sont surtout pour toi, Frédéric, mon fils. Je te les offre avec tout mon amour, pour que tu aies une vision, si petite soit-elle, de la vie de ton père à Alger, pour que tu connaisses un peu mieux tes origines, que tu les perpétues, pour que tu en sois fier.', 19, '978-3-932711-24-4', 1),
(23, 1, 10, 'Dis, c’était comment, l’Algérie française ? 20 questions et réponses à l’intention des jeunes Pieds-Noirs', 'Ce livre est destiné aux jeunes générations des familles françaises qui ont dû quitter l’Algérie après son indépendance en 1962. Sa présentation sous forme de questions et réponses en rend la lecture facile et pratique.\r\nMais ce livre n’est pas pour autant un livre pour enfants car certains passages, et notamment quelques récits rapportés par des témoins d’événements dramatiques, pourraient heurter leur sensibilité.\r\n\r\nIl pourra toutefois aider leurs parents à  répondre aux principales questions qui pourraient leur être posées et à  contribuer ainsi à  rendre justice à  une communauté et à  une page d’histoire trop souvent méconnues, incomprises et décriées. Nouvelle édition revue et corrigée de 2005.', 16, '978-3-932711-25-1', 0),
(24, 1, 11, 'Alger – Marseille. Journal d’une rapatriée', 'Ce journal est le dernier maillon d’une saga familiale, d’une chaîne de Pieds-Noirs implantés en Algérie française de la conquête à  l’indépendance de ce pays. Il s’appuie sur des notes journalières. Son auteur n’est soucieuse que d’objectivité. Si toutefois ses émotions, ses indignations l’emportent parfois du moins s’appuient-elles sur des faits réels, vécus.\r\n\r\nDe 1954 à  1962, Suzon Pulicani-Varnier relate les événements d’Algérie : \r\n- premier soulèvement indigène et massacres d’Européens du 1er novembre 1954, \r\n- généreuse conférence de Camus à  Alger du 21 janvier 1956, \r\n- émouvante fraternisation du 16 mai 1958 et le célèbre « Je vous ai compris » lancé par de Gaulle sur le Forum d’Alger, \r\n- lente dégradation de la situation, \r\n- semaine des barricades (janvier 1960), \r\n- fronde des généraux (avril 1961), \r\n- formation de l’OAS, \r\n- accords d’Evian (19 mars 1962), \r\n- sanglante fusillade de la rue d’Isly (26 mars 1962). \r\n- Enfin, indescriptible panique de juin 1962 jetant des milliers de Pieds-Noirs sur bateaux et avions qui déversent en métropole cette foule de \"rapatriés\" déboussolés et dénués de presque tout.\r\n\r\nDans une deuxième partie de son journal, l’auteur, d’abord désireuse de vivre en Algérie indépendante, décide de gagner la France où lui est offerte une situation qu’elle croit sérieuse mais qui va se révéler illusoire. Sa longue quête d’un emploi trouve une bienheureuse fin dans le poste de secrétaire du Professeur Jean Sutter, chef de la Clinique universitaire de Psychiatrie à  la Timone de Marseille.', 18.5, '978-3-932711-26-8', 1),
(25, 1, 12, 'Il était une fois... ma vie. Alger la Blanche', 'Vous découvrirez ici la vie d’une petite Française que le destin a fait naître, non pas dans un petit village du Jura ou d’Auvergne, mais dans un village de l’autre côte de la Méditerranée, en Algérie, alors française.\r\nLe récit retrace le vécu et le quotidien d’un peuple courageux, turbulent et fier, dans un beau pays qui avait toutes les chances d’être paisible et heureux.\r\n\r\nHélas, les dessous de la politique sont imprévisibles. Et l’Histoire jeta ces hommes, ces Pieds-Noirs, hors de leur terre, démunis et déchirés, révoltés et orphelins.\r\n\r\nVous découvrirez leurs peines, leurs souffrances mais aussi leurs joies et leur ténacité. Et leur vie reconstruite.\r\n\r\nISBN 978-3-932711-27-5', 15, '978-3-932711-27-5', 1),
(26, 2, 13, 'Asche und Glut. Erinnerungen. Résistance und KZ Buchenwald – Fallschirmjäger der Fremdenlegion – Indochina- und Algerienkrieg – Putsch gegen de Gaulle', 'Ruhig, nachdenklich, ohne Pathos und mit kompromissloser Ehrlichkeit skizziert Hélie de Saint Marc die Stationen seines Lebens, in dem sich die Krisen und Umbrüche der französischen Gesellschaft im 20. Jahrhundert widerspiegeln.\r\n\r\n<b>Résistance - Buchenwald - Fremdenlegion</b>\r\n1940 tritt Saint Marc als Achtzehnjähriger in die Résistance ein. 1943 wird er verraten, von der Gestapo verhaftet und nach Buchenwald deportiert. Er überlebt wie durch ein Wunder. Als Absolvent der Militärakademie Saint-Cyr-Coëtquidan beginnt er die Offizierslaufbahn in der Fremdenlegion.\r\n\r\n<b>Indochina- und Algerienkrieg</b>\r\nAb 1948 kämpft Saint Marc in Indochina gegen den kommunistischen Vietminh. Nach dem Desaster von Diên Biên Phu kommt er 1954 nach Algerien zum Einsatz gegen die nationale Befreiungsfront FLN. Unter General Challe ringt die französische Armee die FLN 1959 nieder.\r\n\r\n<b>Putsch gegen de Gaulle und Gefängnis</b>\r\nAls De Gaulle Algerien trotzdem aufgeben will und damit ein menschliches und politisches Fiasko in Kauf nimmt, kommt es im April 1961 in Algier zum Putsch der vier Generäle Challe, Jouhaud, Zeller und Salan, an dem Saint Marc an der Spitze des legendären 1. Fallschirmjägerregiments (1er REP) teilnimmt. Da sich die anderen Generäle zurückhalten, geben die Putschisten auf. Saint Marc stellt sich der Justiz und verbringt über fünf Jahre im Gefängnis.\r\n\r\nHélie de Saint Marc, <i>Grand Croix de la Légion d’honneur</i> (2011), lebte bis zu seinem Tod am 26. August 2013 in Lyon und auf einem kleinen Gut in der Nähe von La Garde-Adhémar (Drôme provençale).\r\nDiese bei Perrin erschienenen Memoiren (<i>Les Champs de braises</i>) avancierten in Frankreich zum Bestseller. Sie wurden mehrfach ausgezeichnet, u. a. 1996 mit dem <i>Prix Fémina</i>.', 25.9, '978-3-932711-50-3', 1),
(27, 2, 13, 'Die Wächter des Abends', '<i>Jeder Mensch möchte in seinem Leben einige Vorstellungen verwirklichen. Doch das Schicksal verändert sie oder stellt sich ihnen in den Weg. Gewissheiten schwinden. Neue geheimnisvolle Rätsel tauchen auf.\r\nSeit 1940 wurde ich mit all den Licht- und Schattenseiten des menschlichen Lebens konfrontiert.\r\nManche Wunden sind noch frisch und schmerzen so sehr, als streue man Salz in sie. Doch andere Schatten und Gestalten halten still Wache. Ich nenne sie meine „Wächter des Abends“. Sie helfen mir zu leben.\r\nIn Vietnam setzen die Bauern stets die Reisschösslinge für die nächste Ernte ein. An jene Menschen dachten Laurent Beccaria und ich, als wir dieses Buch gemeinsam schrieben. Denn diese Seiten haben nur dann einen Sinn, wenn andere Männer und Frauen in ihnen einige Samenkörner finden, die sie an anderer Stelle wieder in den Boden einsetzen.</i>\r\n\r\nHélie de Saint Marc erlebte die großen Krisen Frankreichs im 20. Jahrhundert hautnah mit. Nach dem Einmarsch der deutschen Truppen schloss er sich der Résistance an.\r\n1943 wurde er an die Gestapo verraten und nach Buchenwald deportiert, wo er nur knapp dem Tod entging.\r\nAls Offizier der Fremdenlegion kämpfte er ab 1948 dreizehn Jahre in Indochina und Algerien, zuletzt an der Spitze des in Zéralda (bei Algier) stationierte legendären 1. Fallschirmjägerregiments (1er REP). Nach seiner Beteiligung am Aufstand der vier Generäle Challe, Jouhaud, Zeller und Salan gegen de Gaulles Algerienpolitik 1961 verbrachte er über fünf Jahre im Gefängnis. 1984 wurde er zum <i>Commandeur de la Légion d’honneur</i> ernannt, 2011 erhielt er das <i>Grand-Croix de la Légion d’honneur</i>.\r\nEr lebte bis zu seinem Tod am 26. August 2013 in Lyon und in der Nähe von <b>La Garde Adhémar</b> (Les Borias, Drôme provençale), wo er auch begraben ist.', 16, '978-3-932711-51-0', 1),
(28, 7, 14, 'La France et la Tierce Allemagne à  l’exemple de la Saxe entre 1814 et 1886', 'Le présent ouvrage porte sur les relations entre la France et la Tierce Allemagne à  l’exemple de la Saxe entre 1814/1815 et 1866. Il a pour but de revaloriser le rôle des petits états allemands, longtemps négligés par l’historiographie française et allemande.\r\n\r\nCes états allemands, tels que la Saxe, la Bavière ou la Hesse tentèrent de jouer un rôle indépendant entre la Prusse et l’Autriche, en tant que «Tierce Allemagne» (ou <i>Trias</i>). Cette volonté politique allait dans le sens de l’intérêt de la France qui s’efforçait depuis Richelieu à  éviter toute union politique et économique allemande.\r\n\r\nL’idée de Trias ne dépassa pourtant pas le stade de concept politique car ces petits et moyens états ne parvinrent jamais à  une position commune et la France n’apporta jamais le soutien nécessaire à  ce projet.\r\n\r\nOlvier Podevins, né en 1969, a suivi des études d’histoire et de sciences politiques à  Lille, Frankfurt/Main et Strasbourg.\r\nCe travail de doctorat fut réalisé à  l’université technique de Dresde au sein de la chaire d’Études sur la France et la Francophonie.', 25.15, '978-3-932711-53-4', 1),
(29, 1, 26, 'Une histoire souterraine. Pieds-Noirs et Musulmans en Algérie', '<em>« En Algérie, là où les deux communautés se rencontraient chaque jour, une histoire s’est déroulée, cachée, souterraine, faite souvent de compréhension, d’écoute, de tendresse et parfois d’amour et de nostalgie. »</em> (Jean Pélégri)\r\n\r\nChacun à sa manière, Jean Brune, Michèle Piris-Lambert, Marie-Anne Lorentz, Jean Pélégri, Marie-Louise de Pena et Hélie de Saint Marc évoquent cette histoire souter­raine qui se prolonge bien au-delà de l’exode douloureux des Pieds-Noirs en 1962.\r\nCe recueil de textes, dont plusieurs sont encore inédits, constitue un témoignage littéraire émouvant et indis­pensable pour la compréhension de cette relation complexe entre les deux communautés.', 14.5, '978-3-932711-17-6', 1),
(30, 1, 0, 'Le sel des Andalouses', '<b>Préface de Boualem Sansal</b>\r\n\r\nEndormi dans une morne existence parisienne, Marc va voir sa vie bouleversée par la mort de son père. Ce fils de Pied-Noir s’engage, dès lors, dans une quête initiatique qui va le conduire de l’autre côté de la Médi­ter­ra­née, en Kabylie, à Alger et surtout à Oran, où, sur la Plage des Andalouses, il fera une rencontre décisive qui le liera plus que jamais à la terre de ses ancêtres.\r\n\r\nOù Marc sera-t-il entraîné par l’amour, l’amitié et la fidélité aux siens ?\r\n\r\nRetrouvailles exaltantes avec des racines oubliées, plongée au cœur d’événements qui secouent l’Algérie d’aujourd’hui et appellent à revisiter ceux qui la déchirèrent hier, ce roman offre un regard nouveau et fascinant sur ce pays et tous ceux qui y vécurent et continuent à y vivre.', 20, '978-3-932711-28-2', 1),
(31, 1, 0, 'La lettre à  un père disparu', 'Ce texte, qui figure aussi intégralement dans le roman de Maurice Calmein, <i>Le sel des Andalouses</i>, a été écrit en 2004 pour être lu à  l\'occasion du <i>Colloque sur les disparus d\'Algérie</i>. Lors de l\'inauguration du <i>Mur des disparus</i>, en 2007 à  Perpignan, il fut à  nouveau lu pour les 7000 personnes présentes à  cet événement.\r\n\r\n<i>La lettre à  un père disparu</i> n\'est pas le témoignage d\'une situation vécue mais un récit imaginaire.\r\nElle exprime cependant avec beaucoup de réalisme les pensées et les sentiments qui ont pu traverser l\'esprit d\'un enfant confronté au drame de la disparition d\'un père à  la fin de la guerre d\'Algérie.', 6, '978-3-932711-54-1', 1),
(32, 1, 19, 'Algérie, histoires à ne pas dire... Le film choc interdit en Algérie. Scénario - réactions - polémiques', '<b>Préface de Boualem Sansal</b>\r\n\r\nEn 1962, l’Algérie devient indépendante. Quasiment tous les non-Musulmans quittent l’Algérie : l’un des plus importants déplacements de population dans l’histoire de l’Humanité.\r\n\r\n<b>Pourquoi l’Algérie n’a-t-elle pas réussi à être aussi fraternelle ?</b>\r\nLa cohabitation avec les Musulmans y avait-elle été impossible ? Cette triste fin n’avait-elle été que l’effet d’une panique, des violences extrêmes de fin de guerre ?\r\nQuatre Algériens en quête de vérité reviennent sur les mythes fondateurs de l’Algérie nouvelle et des crimes cachés de cette «guerre de libération» <strong>qui fut aussi une guerre d’épuration ethnique contre la population non-musulmane </strong>:\r\no Les massacres à <b>El Halia (Philippeville)</b>, le <b>20 août 1955</b>\r\no Les <b>attentats à la bombe</b> et la <b>Bataille d’Alger (1956–1957)</b>\r\no L’assassinat du chanteur juif <b>Raymond Leyris</b> à Constantine, le <b>22 juin 1961</b>\r\no Les massacres à <b>Oran</b>, le <b>5 juillet 1962</b>.\r\n\r\n<i>\"La parole qui se dit là , libre, mouvementée, chahutée et ballottée par l’Histoire ou par des retrouvailles souvent douloureuses avivant les plaies familiales, cette parole-là est essentielle.\r\nNous n’avons pas souvent l’occasion ou la chance de l’entendre venant d’Algérie.\r\nC’est ce qui fait le prix et l’importance du film de Jean-Pierre Lledo, à voir coûte que coûte.\"</i> (Serge Toubiana, Directeur de la Cinémathèque française)\r\n\r\n<b>Jean-Pierre Lledo</b> est né en 1947 à Tlemcen.\r\nAlgérien depuis le 6<sup>e</sup> siècle avant l’ère commune, par ses ancêtres maternels juifs, et depuis 1848, par les paternels catalans.\r\nÀ la suite de menaces islamistes, Jean-Pierre Lledo a dû quitter l’Algérie en 1993.\r\nDepuis, il a réalisé plusieurs films documentaires liés aux réalités multiethniques de l’Algérie d’avant 1962, mémoires refoulées par l’histoire officielle.', 20, '978-3-932711-31-2', 1),
(33, 1, 0, 'La Traversée de Fiora Valencourt', '<b>Préface de Maurice Calmein.</b>\r\n\r\nSera-t-elle la dernière de sa vie, cette traversée Marseille–Oran qu’entreprend Mme Valencourt au printemps 1961 pour regagner son pays natal ?\r\nAutour d’elle, sur le paquebot, la vieille dame ne rencontre que les visages soucieux des Français d’Algérie, tendus dans l’angoisse du lendemain. Elle, elle s’évade dans son passé, un passé qui fut tout amour et ce livre ne pourrait être que la belle histoire de deux êtres qui s’aimèrent, jadis, dans les champs d’alfa des hauts plateaux oranais, si le présent ne ternissait l’éclat du ciel et du soleil sur la mer.\r\n\r\nQui veut savoir et comprendre qui sont véritablement les Français d’Algérie, doit lire ce livre.\r\n\r\nLorsque ce roman parut pour la première fois, en 1961, on ne savait pas encore ce qu’allait devenir l’Algérie ni ce qu’il adviendrait d’un million de Pieds-Noirs pour qui ce pays était le leur. Ils l’avaient créé et mis en valeur.\r\nLa réédition de ce livre en 2011 ne le rend que plus authentique dans la mesure où ne s’y mêlent pas encore les considérations politiques qui allaient déchirer les Français en 1962.\r\n\r\nJanine Montupet, par toutes ses fibres, appartient à la terre d’Algérie. Ses ancêtres s’y sont installés dès 1848.\r\nAu travers de cette grande fresque romanesque que constitue la trilogie <i>La Fontaine rouge</i>, Janine Montupet a imaginé de nous décrire les propriétaires successifs du domaine de la Fontaine rouge située dans la plaine de la Mitidja.\r\n<i>La Traversée de Fiora Valencourt</i> vient clore cette grande saga algérienne.\r\n\r\nCollection France-Algérie 29', 27, '978-3-932711-29-9', 1),
(34, 1, 0, 'Algériens nous sommes... qué! Histoire de l\'Algérianisme', 'Ce petit livre retrace toute l\'histoire de <b>la littérature française d\'Algérie</b> et du <b>mouvement algérianiste</b>, depuis ses origines dans les années 1920 jusqu\'à nos jours.\r\nOutre une bibliographie sur le sujet et la liste des prix littéraires algérianistes d\'hier et d\'aujourd\'hui, cet ouvrage reproduit également en annexe le petit fascicule <b><i>L\'Algérianisme</i></b> publié par <b>Jo Sohet</b> en <b>1991</b>, alors président national du Cercle algérianiste.\r\n\r\nUne des répliques les plus célèbres de <b>Cagayous</b>, ce héros turbulent et malicieux de Musette (alias Auguste Robinet), fut la réponse qu’il fit, en visite à l’Exposition universelle de Paris, à un quidam étonné par son accent algérois et qui lui demandait s’il était Français :\r\n<i><b></b></i>\r\n\r\n<center>« Algériens nous sommes… qué ! »</center><b>Maurice Calmein</b> est né en 1947 à Oran. En 1960, sa famille s’installe à Toulouse où, dès l’âge de vingt ans, il milite dans des associations de Français d’Algérie. Président de l’Amicale universitaire pied-noir, il rencontre <b>Jean Pomier</b>, l\'un des fondateurs du mouvement algérianiste, dont il devient l’ami malgré leurs soixante ans d’écart. Il fondera lui-même le Cercle algérianiste quelques années plus tard et Jean Pomier en sera le président d’honneur.\r\nMaurice Calmein est l’auteur de plusieurs livres sur l’Algérie, dont le roman <i><b>Le Sel des Andalouses</b></i>. Il a assuré l’éditorial de la revue <i>L’Algérianiste</i> pendant plus de dix ans.\r\n\r\nCollection France-Algérie 30.', 13, '978-3-932711-30-5', 1),
(35, 1, 0, 'Jean Brune, Français d\'Algérie. Biographie', '«La seule défaite irréparable, c’est l’oubli.» (Jean Brune, <i>La guerre de Troie commence demain</i>)\r\n\r\nJean Brune est né le 12 mars 1912, à  Aïn Bessem, et décédé à  Nouméa, le 23 septembre 1973, miné par la perte de son Algérie, de notre Algérie française, pour laquelle il s’était tant battu et avait tant espéré un destin fraternel.\r\n\r\nAu dixième anniversaire de sa disparition, j’ai tenté de fixer cet être divers, artiste au crayon léger, maître des mots porteurs d’idées fortes, homme riche de cœur, dans un ouvrage paru en 1983 et aujourd’hui totalement épuisé.\r\n\r\nLe voici réédité en ce mois de mars anniversaire de sa naissance, et en cette année 1998, la vingt-cinquième, depuis que des mains amies et des cœurs en peine, l’ont déposé dans le petit cimetière de Païta. Aux souvenirs confiés à  moi par ceux qui l’ont aimé s’ajoutent, cette fois, des croquis de guerre pris sur le vif quand, dans un char de la Première Division blindée, il débarqua sur les côtes de Provence le 15 août 1944, avec tous les autres Français d’Algérie qui, d’un seul élan, venaient <i>\"participer aux pompes bouleversantes de la bataille de la Libération\"</i>.\r\n(Francine Dessaigne) - édité aux éditions Confrérie Castille (Ivry-sur-Seine) en 1998 - 270 pages, plusieurs croquis', 17, '2907862421', 1),
(36, 3, 0, 'Nouveau Blason Pied-Noir ', '<b>Le nouveau blason pied-noir\r\ndisponible en autocollant (environ 10 cm x 7 cm)\r\naux Éditions Atlantis.</b>\r\n\r\nVoici les prix TTC frais de port inclus :\r\n\r\n5 autocollants à 3,50 €\r\n10 autocollants à 6,00 €\r\n20 autocollants à 9,00 €\r\n\r\nEnvoyez un chèque à l’adresse suivante, S.V.P. :\r\n\r\nEditions Atlantis\r\nGeltendorfer Strasse 17\r\n86316 Friedberg\r\nAllemagne', 1, 'autocollant', 1),
(37, 1, 19, 'Grand-Père a tué deux \"colons\". 8 mai 1945 en Algérie : l\'insurrection commence avec le massacre des innocents. Avec une analyse de \"Hors-la-loi\"', '<b>8 mai 1945 : de nouvelles histoires à ne pas dire…</b>\r\n\r\nDans <i><b>Algérie, histoires à ne pas dire</b></i>, pour la première fois au cinéma, des Algériens musulmans racontaient les massacres qu’ils ont commis à l’encontre de civils européens pendant la guerre d’Algérie (1954-1962).\r\n\r\nLe <b>livre-DVD <i>Grand-Père a tué deux \"colons\"</i></b> révèle de nouvelles \"histoires à ne pas dire\" qui se situent pendant l’insurrection manquée du 8 mai 1945 dans la région de Chevreul (Béni-Aziz). Ahmed Zir, le protagoniste de ces séquences, part à la recherche de l’histoire de son grand-père : celui-ci a-t-il vraiment tué deux colons avant d’être exécuté à son tour par l’armée française à\r\n\r\nPlusieurs témoins musulmans évoquent avec gêne le sort déshonorant que les insurgés réservaient à leurs victimes européennes dans ce véritable Djihad. Un chef local avoue aussi avoir été sauvé in extremis de l’exécution par son employeur pied-noir, lors d’une action de riposte de l’armée française.\r\n\r\nEn faisant voler en éclats l’histoire officielle algérienne de mai 1945, ce livre-DVD est un hommage à toutes les victimes innocentes – celles de l’insurrection musulmane, tout comme celles de la répression par l’armée française.\r\n\r\nDans ce livre, vous trouverez :\r\n\r\n- un DVD de Jean-Pierre Lledo (58 minutes) ;\r\n\r\n- le scénario complet du DVD avec 50 photos ;\r\n\r\n- plusieurs documents, analyses et commentaires sur l\'insurrection du 8 mai 1945 à Chevreul (Béni-Aziz) et à Sétif de <b>Jean-Pierre Lledo, Roger Vétillard</b> et <b>Maurice Villard</b> ;\r\n\r\n- des extraits de <i><b>Mon testament</b></i> de <b>Ferhat Abbas</b> concernant l\'insurrection de mai 1945 ;\r\n\r\n- une analyse de <b>Wolf Albes</b> du film <i><b>Hors-la-loi</b></i> de Rachid Bouchareb (50 pages) ;\r\n\r\nLivre-DVD : 230 pages et 50 photos dont certaines en couleur\r\n\r\nCollection France-Algérie 34', 29, '978-3-932711-34-3', 1),
(38, 1, 0, 'Les oranges amères de Blida', '<b>À travers mon histoire, c’est l’histoire de beaucoup de mes camarades de combat civils ou militaires qui, dans l’ombre, ont essayé de sauver l’Algérie française.\r\nCertains y ont laissé leur vie, d’autres ont fait de la prison et d’autres, chanceux, sont passés au travers de tout.\r\nC’est à eux tous que je veux rendre hommage. </b>\r\n\r\n<i>« Jusqu’à présent, je ne suis jamais arrivé à raconter cette histoire jusqu’au bout, tellement l’émotion me prend à la gorge.\r\nEt là de nouveau tout surgit devant moi, la guerre, les trahisons, l’insécurité permanente, le risque de se faire enlever, de se faire arrêter et toute cette atmosphère de débandade générale, les tas d’ordures qui brûlent sur les trottoirs, une ville qui se meurt, les avions et les bateaux au compte-goutte, les amis qui sont morts, ceux qui ont été enlevés… Comment peut-on pardonner ?… »</i>\r\n\r\nÀ partir d’octobre 1960, le sous-officier de l\'Armée de l\'Air Henri Mazzarino organise la résistance à Blida. Quelques mois plus tard, « Mazza » rejoint l’OAS avec son groupe. En octobre 1961, il déserte et passe dans la clandestinité. Blida sera la <em>\"seule ville où l’OAS prend un caractère représentatif\"</em> (Pierre Montagnon, <i>La Guerre d’Algérie</i>).\r\n\r\nDans ce livre, il décrit son parcours entre 1958 et 1964, un parcours qui fut très dangereux, parfois rocambolesque, souvent émouvant.\r\n\r\nCollection France-Algérie 32\r\n\r\nNouvelle édition revue et corrigée de 2014 !', 17, '978-3-932711-32-9', 1);
INSERT INTO `publikationen` (`pub_id`, `kat_id`, `aut_id`, `titel`, `text`, `preis`, `isbn`, `available`) VALUES
(39, 1, 0, 'Mon paradis perdu. Une enfance algérienne. Oran 1954 - 1962. Préface de Maurice Calmein', '<b><i>J\'aurais pu être heureuse…</b>\r\n<i>« Je dormais à  côté des fées. Elles fleurissaient sur le rebord de la fenêtre de ma chambre au rez-de-chaussée de notre maison. Les \"grands\" disaient que c\'étaient seulement des fleurs, des fuchsias, mais avec ce nom, je savais qu\'elles étaient extraordinaires. \r\nD\'ailleurs, elles me l\'avaient dit… pendant mon sommeil. » </i>\r\n\r\nJ\'aurais pu être heureuse…\r\n\r\nMais je suis née le 9 mai 1954 à  Oran, en Algérie française. Et je ne pouvais pas savoir qu’à  peine six mois plus tard allait débuter la guerre pour l\'indépendance.\r\nEt puis ma grand-mère régnait sur notre famille en imposant sa tyrannie. \r\nC\'est pour m\'échapper de la peur qu\'elle m\'inspirait que je trouvais une raison de vivre dans l\'art, le piano, la danse et surtout l\'écriture.\r\nJ\'ai vu le ciel pur de mon enfance se charger d\'ombres, d\'inquiétudes, des nuages noirs des incendies, des rafales de mitraillettes. \r\nEt la Méditerranée représentait la menace d\'un exil qui nous guettait comme le Destin. \r\nLe Destin s’est accompli et le paradis de mon enfance fut définitivement perdu.\r\n\r\nJ\'ai dû attendre une cinquantaine d\'années pour avoir la force d\'affronter ces souvenirs.\r\n\r\n<b>Je suis toujours l\'enfant devant une mer immense, appuyée sur un arbre mort en face de l\'Histoire. </i></b>\r\n\r\n\r\n<b>Histoire d\'une enfance brisée</b>\r\nMonique Clavaud est née à  Oran en 1954, six mois avant le début d’une insurrection qui allait changer le destin d’un peuple. \r\nDans son regard d’enfant se mêlent alors la famille, les proches, les jeux et petits malheurs quotidiens, les images et les odeurs du pays mais aussi, en toile de fond, les événements qui secouent l’Algérie. Ils font de temps à  autre une incursion furtive et brutale dans la vie de cette petite fille qui n’en comprend pas pour autant le sens, jusqu’au jour de l’arrachement, en 1962. \r\nCette rupture laissera une part de cette enfance de l’autre côté de la Méditerranée mais l’autre part s’est figée au cœur de l’adulte, avec une sensibilité intacte. \r\nC’est cette sensibilité qu’exprime Monique Clavaud dans ce récit d’une enfance brisée, rattrapée par la folie des grands, dans l’histoire d’une famille prise dans la tempête de l’exode et d’une grande page d’histoire déchirée.\r\n<i>Maurice Calmein</i>\r\n\r\nCollection France-Algérie 35\r\n\r\n100 pages - avec 8 photos', 17, '978-3-932711-35-0', 1),
(40, 1, 0, 'Les Français d\'Algérie. De 1962 à  2014', '<b>Une plaie toujours béante...</b>\r\n\r\nPréface de Thierry Rolando, président national du Cercle algérianiste.\r\n\r\n- Qui sont les Pieds-Noirs, ces Français exilés d’Algérie en 1962 après 132 ans de présence de la France dans ce pays qu’ils avaient créé et 8 ans d’une guerre civile qui le déchira ?\r\n- Pourquoi les appelle-t-on ainsi ?\r\n- Que furent exactement leur histoire et la tragédie de leur exode ?\r\n- Comment se sont-ils insérés dans l’hexagone ?\r\n- Quelles sont les motivations qui les poussent à se regrouper et à se battre pour la sauvegarde de leur identité, de leur culture et de leur mémoire collective ?\r\n- Que reste-t-il de cette culture, des traditions, de la personnalité de ce peuple déraciné ?\r\n- Quelles sont, aujourd’hui encore, leurs revendications mais aussi celles des Harkis, leurs frères d’infortune ?\r\n- Quels sont leurs sentiments à l’égard des Algériens, de l’Algérie et de la France, leurs attitudes politiques ?\r\n- Quelles sont les raisons de leur colère, les dossiers encore en instance ?\r\n- Que deviennent leurs cimetières laissés outre-Méditerranée ?\r\n- Que sont leurs associations, leurs rassemblements, leurs journaux, leurs sites Internet à Comment se situent leurs enfants et petits-enfants ?\r\n- Ce peuple de pionniers coupé de ses racines a-t-il un avenir ?\r\n\r\nC’est à toutes ces questions que Maurice Calmein a voulu répondre dans ce livre, pour sortir de l’ornière de la désinformation qui a trop longtemps étouffé cette page de l’histoire de France et donner la parole à ces Français d’Algérie encore bien méconnus de leurs concitoyens métropolitains.\r\n\r\nCes réponses sont d’autant plus étayées que l’auteur, né en 1947 à Oran, est l’un d’eux et a milité depuis l’âge de 16 ans dans des mouvements pieds-noirs. Il en a même créé et animé plusieurs. Ce livre est le quatrième qu’il consacre à ses compatriotes et à l’histoire de l’Algérie française .\r\n\r\nMaurice Calmein est chevalier de la Légion d’honneur et de l’Ordre national du Mérite.\r\n\r\n432 pages, plusieurs photos, cartes etc.\r\n\r\nNouvelle édition revue et corrigée de l\'édition de 2012.\r\n\r\nCollection France-Algérie 38<b> </b>', 25, '978-3-932711-38-1', 1),
(41, 1, 0, 'Exode', '<center><b><i>Ils étaient vingt et cent, ils étaient des milliers,\r\nDisait une chanson, il y a quelques années.\r\nCela parlait d’un autre drame de l’histoire\r\nCar pour ce qui est du nôtre, on n’en parle nulle part.\r\nEt pourtant, sous un triste soleil de juillet,\r\nIl y a cinquante ans, eux aussi… Écoutez :...</center></i>\r\n\r\nC\'est ainsi que commence <i>Exode</i> de Maurice Calmein, présenté pour la première fois devant un auditoire profondément ému au 38<sup>e</sup> Congrès Algérianiste, le 27 janvier 2012.\r\n\r\n</b>8 pages - carton de 200g, laqué, brillant.\r\n\r\n© Edition Atlantis - Maurice Calmein\r\n\r\nFrais de port : 2 €*\r\n\r\n*Quel que soit le nombre d\'exemplaires commandés. \r\nSi vous commandez encore d\'autres livres sur le site, l\'envoi d\'<i>Exode</i> est, bien entendu, gratuit.\r\n', 3, 'exode', 1),
(42, 4, 0, 'Les maux pour le dire. Chroniques de Cicéron pour la défense du français. ', 'Sous le pseudonyme du grand rhétoricien Cicéron, Maurice Calmein a publié pendant deux ans dans la <i>Voix du Midi-Lauragais</i> la chronique « Les maux pour le dire ». \r\n\r\nDans ses billets incisifs et humoristiques, il s’en prend aux dérives actuelles de la langue française, à  l’invasion des anglicismes et à  une certaine pédanterie du langage préjudiciable à  une simple et bonne communication.\r\n\r\nLe succès remporté par cette chronique auprès des lecteurs du journal a fait naître l’idée de regrouper 90 de ces billets dans le présent recueil. ', 12, '978-3-932711-60-2', 1),
(43, 5, 0, '« Pour moi, Wernher von Braun est un criminel de guerre. » - Interview d‘André Laroche, rescapé de Dora (Lyon - octobre 2012)', 'André Laroche naît le 3 mai 1924 à  Lyon. \r\nEn juillet 1941, il rejoint le mouvement Combat. \r\nLe 29 mars 1944, la Milice de Paul Touvier l’arrête à  Lyon. Il est interrogé par la Gestapo, interné à  Montluc et à  Compiègne, puis déporté à  Buchenwald. \r\nEn juillet 1944, il est transféré à  Mittelbau-Dora où il doit travailler comme soudeur dans le « tunnel » où sont assemblées les V1. \r\nA l’approche de l’Armée rouge, en avril 1945, commence pour lui la marche de la mort. Il survit comme par miracle. À son retour à  Lyon, il pèse 34 kilos…\r\nAprès la guerre, André Laroche devient chef d\'entreprise et s’investit dans le milieu associatif. Il est nommé président de la Fédération Nationale des Déportés et Internés de la Résistance, vice-président du Comité d\'Action de la Résistance, vice-président de la Commission Exécutive du Struthof, et président d\'Honneur du Mouvement d\'Union et d\'Action des Déportés et Internés de la Résistance à  Lyon. (voir aussi : http://www.chrd.lyon.fr)\r\n\r\nDans cette interview, André Laroche raconte son calvaire au camp de Dora, ce qu\'il pense de Wernher von Braun et du fait qu\'un lycée allemand, le Wernher-von-Braun-Gymnasium à  Friedberg (Bavière), porte aujourd\'hui encore le nom de celui qui, pour lui, est un criminel de guerre.\r\n\r\nHinweise:</b>\r\nAlle Rechte beim Verlag EditionAtlantiS November 2012.\r\nKeine Reproduktion oder anderweitige Verwendung des Interviews ohne vorherige Genehmigung der EditionAtlantiS.\r\nAussagen in Interviews spiegeln ausschließlich die Meinung des Interviewpartners wider. \r\nFür die Inhalte externer Links ist keine Haftung möglich. \r\nFür die Inhalte der verlinkten Seiten sind ausschließlich deren Betreiber verantwortlich.\r\nSollten Inhalte verlinkter Seiten rechtlich beanstandenswert sein, informieren Sie bitte <b>editions.atlantis@orange.fr</b> !\r\n', 0, 'interview', 1),
(44, 5, 0, '\"Wie kann man nur eine deutsche Schule nach Wernher von Braun benennen?\" - Interview mit André Laroche, einem Überlebenden des KZ Mittelbau-Dora', '<b>André Laroche</b> (geb. am 3.5.1924 in Lyon) tritt im Juli 1941 in die bedeutendste französische Widerstandsgruppe <i><b>Combat</i></b> innerhalb der damals noch unbesetzten Zone ein und kümmert sich hauptsächlich um die Verbreitung der gleichnamigen Zeitung. \r\n\r\nAm 29. März 1944 wird er von der französischen Milice in Lyon verhaftet, von der Gestapo verhört und über Montluc und Compiègne im Mai nach <b>Buchenwald</b> deportiert. \r\nIm Juli 1944 kommt er nach <b>Mittelbau-Dora</b> und muss im berüchtigten „Tunnel“ als Schweißer in der Produktion der V1 arbeiten. \r\nIm April 1945 wird das Lager von der SS geräumt, die Häftlinge müssen sich auf den Todesmarsch begeben. Laroche überlebt wie durch ein Wunder. Bei seiner Rückkehr nach Lyon wiegt er noch 38 kg.\r\nNach dem Krieg kehrt er wieder als Industrieschreiner in seine alte Firma zurück und übernimmt sie. Im Verlauf der nächsten Jahre gründet er weitere sechs erfolgreiche Möbelfirmen um Umkreis von Lyon, in denen auch zahlreiche ehemalige Deportierte Arbeit finden - u. a. vorübergehend auch <b>Hélie de Saint Marc </b>(siehe seine beiden Werke <b><i>Asche und Glut</b></i> und <i><b>Die Wächter des Abends</b></i>, erschienen in deutscher Übersetzung in der EditionAtlantiS). \r\nEr erhält mehrere hohe Auszeichnungen und bekleidet Spitzenämter in verschiedenen Vereinigungen ehemaliger Widerstandskämpfer in Paris, Lyon und Struthof.\r\n\r\nDas vorliegende Interview wurde aus Auszügen aus zwei Gesprächen mit André Laroche in La Garde-Adhémar (am 6. September 2012) und in Lyon (17. Oktober 2012) zusammengestellt. Inhaltlich konzentrieren sich diese Auszüge auf Laroches Schilderung des Alltags und seiner Tätigkeit als Schweißer in Dora und seine Auseinandersetzung mit Wernher von Braun und der Problematik der Namensgebung des Wernher-von-Braun-Gymnasiums in Friedberg (Bayern).\r\n\r\nInterview und Übersetzung aus dem Französischen: Wolf Albes. \n\r\n\r Hinweise:</b>\r\nAlle Rechte beim Verlag EditionAtlantiS November 2012.\r\nKeine Reproduktion oder anderweitige Verwendung des Interviews ohne vorherige Genehmigung der EditionAtlantiS.\r\nAussagen in Interviews spiegeln ausschließlich die Meinung des Interviewpartners wider. \r\nFür die Inhalte externer Links ist keine Haftung möglich. \r\nFür die Inhalte der verlinkten Seiten sind ausschließlich deren Betreiber verantwortlich.\r\nSollten Inhalte verlinkter Seiten rechtlich beanstandenswert sein, informieren Sie bitte <b>editions.atlantis@orange.fr</b> !', 0, 'interview2', 1),
(45, 1, 0, 'Algérie 1962. Journal de l\'Apocalypse / Tagebuch der Apokalypse. Préface de Boualem Sansal / Vorwort von Boualem Sansal', 'Nicole Guiraud est née en 1946 aux Vergers, dans le Sahel algérois, descendante d’une lignée de pionniers enracinés dans le pays depuis cinq générations. À 10 ans, elle est grièvement blessée dans l’attentat du Milk Bar, le 30 septembre 1956 à Alger.\r\nDans son <i><b>Journal de l\'Apocalypse</b></i>, elle retrace les violences de la guerre civile entre avril et juin 1962 à Alger qui mènera à l’exode des Français d’Algérie.\r\nArtiste plasticienne, elle témoigne de la mémoire oubliée d’une Algérie plurielle, avec ses moments de bonheur intense et ses déchirements cruels.\r\n\r\nNicole Guiraud wird 1946 in Les Vergers, im Sahel algérois, geboren. Ihre Familie ist bereits in der fünften Generation in Algerien ansässig. Als Zehnjährige wird sie in Algier beim Attentat der FLN auf die Milk Bar am 30. September 1956 schwer verletzt.\r\nIn ihrem <i><b>Tagebuch der Apokalypse</b></i> schildert sie die Gewalt des Bürgerkriegs 1962 in Algier, der mit dem schmerzlichen Exodus der Algerienfranzosen endet.\r\nHeute lebt sie als bildende Künstlerin in Montpellier und Frankfurt/Main. In ihren Werken beschwört sie die Erinnerung an das berauschende Glück und das grausame Leid in ihrer einst kulturell so vielfältigen algerischen Heimat.\r\n\r\nCollection France-Algérie 36. Édition bilingue (français/allemand)\r\nZweisprachige Ausgabe (französisch/deutsch)\r\n\r\n106 pages/ 106 Seiten.\r\nAvec 44 illustrations dont 24 en couleur. / Mit 44 Abbildungen, davon 24 farbig.\r\n\r\n&nbsp;\r\n\r\n<span style=\"font-size: 18pt;\"><strong><span style=\"color: #ff0000;\">Diary of Apocalpyse :</span></strong></span>\r\n\r\nUne <span style=\"color: #ff0000;\"><strong>version anglaise</strong></span> du texte, établie par <strong>Amy L. Hubbell</strong> et <strong>Muhib Nabulsi</strong> avec un groupe d\'étudiants australiens de l\'<strong>Université de Queensland</strong> est désormais disponible (voir en bas, texte numéro 3).\r\n\r\nEine <span style=\"color: #ff0000;\"><strong>englische Version </strong></span>des Textes, die von <strong>Amy L. Hubbell</strong> und <strong>Muhib Nabulsi</strong> zusammen mit einer Gruppe australischer Studenten der <strong>University of Queensland</strong> erstellt wurde, ist nun ebenfalls verfügbar (siehe weiter unten, 3. Text).', 17, '978-3-932711-36-7', 1),
(46, 1, 0, 'Oran 1961-1962. Journal d’un prêtre en Algérie', 'Le Père <b>Michel de Laparre de Saint Sernin </b>fut envoyé par l\'église de France comme curé d\'une paroisse à Oran en 1961, au moment de la fin de la présence française en Algérie. Il arrive dans une ville en état de siège, où le FLN, l’ALN, l’OAS, l’Armée française, les CRS, les Gardes mobiles, les ATO (Auxiliaires Temporels Occasionnels) et les barbouzes s’affrontent dans une lutte meurtrière. Du 5 juillet 1961 jusqu’au 19 août 1962, il notera presque au jour le jour ses observations et ses réflexions.\r\n\r\nCe témoignage authentique réserve beaucoup de surprises pour tous ceux qui cherchent à savoir et à comprendre ce qui s’est vraiment passé pendant la guerre d’Algérie. Il fait voler en éclats les déformations et diffamations de certains historiens \"politiquement corrects\".\r\n\r\nLe texte inédit <b><i>Misères de la guerre d’Algérie</i></b> de <b>Jean Brune</b> ainsi que 22 gravures de <b>Jean François Galéa</b> sur les horreurs de la guerre d’Algérie viennent enrichir cette nouvelle édition.\r\nCes dernières nous donnent une idée des atrocités commises par le FLN contre les civils européens et musulmans.\r\n\r\nParu le 15 mai 2013.', 22, '978-3-932711-37-4', 1),
(47, 6, 2, 'L\'Hôte. La nouvelle d’Albert Camus et la bande dessinée de Jacques Ferrandez dans le contexte colonial', '<span style=\"color: #ff0000;\"><strong>Kostenloser Versand:</strong></span>\r\n\r\n<span style=\"color: #ff0000;\"><strong>Bei Bestellung auf Rechnung über <span style=\"color: #0000ff;\">contact@editionatlantis.de</span> ist der Versand kostenlos.</strong></span>\r\n\r\n&nbsp;\r\n\r\n<b>Préface d\'Hubert Ripoll.</b>\r\n\r\nAvec la participation de Maurice Calmein, Roger Vétillard, Luc Verlinde, Georges Hirtz, Odette Caparros, Jean Monneret et Jean-Jacques Jordi.\r\n\r\n<b><i>L\'Hôte</i> : l\'instituteur Daru entre deux feux</b>\r\n\r\nAlgérie, 1946 : Depuis un an, l\'instituteur Daru vit seul dans son école perdue sur les Hauts-Plateaux où il accueille des enfants musulmans des villages avoisinants.\r\nÀ la mi-octobre, le gendarme Balducci se présente chez lui avec un prisonnier arabe. Daru les accueille en hôtes.\r\nIl apprend par la suite que l’Arabe a tué son cousin et qu\'il doit le conduire à la prison de Tinguit parce que le gendarme doit retourner à son poste à cause d’un soulèvement.\r\nCependant, Daru refuse de livrer son hôte parce que <i>\"c’est contraire à l’honneur\"</i>.\r\nLe gendarme repart : il est vexé mais il ne dénoncera pas son ami.\r\nDaru se voit donc contraint d\'héberger l\'Arabe, de lui préparer le repas et même de passer la nuit à côté de lui. Son prisonnier en profitera-t-il pour s\'enfuir ?\r\nNon, le lendemain matin, il est toujours là .\r\nDaru finit par le mener à une bifurcation où il doit choisir d\'aller se rendre aux autorités ou de se réfugier chez les nomades. Daru repart chez lui mais, inquiet, revient sur ses pas et aperçoit <i>\"l’Arabe qui cheminait lentement sur la route de la prison\".</i>\r\nEn rentrant à son école, il découvre des menaces de vengeance inscrites sur le tableau.\r\nPoursuivi par les proches de l’Arabe, qui croient qu’il a livré l\'un des leurs, et désavoué par ses compatriotes qui l’accuseront de les avoir trahis face à l\'insurrection, Daru est désormais seul.\r\n\r\n<b>L\'analyse de la nouvelle</b>\r\n\r\n– Qui est cet Arabe <i>\"à la bouche animale\"</i> qui a tué son cousin <i>\"pour du grain\"</i> ou pour des <i>\"affaires de famille\"</i> ?\r\n– Comment se présente son meurtre à la lumière du Coran ?\r\n– Pourquoi l\'Arabe ne se réfugie-t-il pas chez les nomades comme le lui suggère Daru ?\r\n– Quels sont le \"message\" et la portée politique de la nouvelle dans le contexte de la guerre d\'Algérie ?\r\n– Pourquoi avoir choisi les Hauts-Plateaux et \"Tinguit\" – dans le manuscrit Trézel – comme lieu de l\'action ?\r\n– Quel est ce \"soulèvement\" de 1946 ?\r\n\r\nL\'auteur essaie de donner des réponses à toutes ces questions et à bien d\'autres encore en procédant à une analyse approfondie de la nouvelle et de sa genèse dans le contexte colonial, enrichie par une minutieuse comparaison de la nouvelle avec la bande dessinée de Jacques Ferrandez.\r\n\r\nLe lecteur trouvera dans cet ouvrage une partie \"Analyses et documents\" de 140 pages contenant entre autres :\r\n– Une importante chronologie de l’Algérie et de la guerre d\'Algérie (1954-1962) (54 pages).\r\n– Des extraits commentés des œuvres de Mouloud Feraoun, Jean Brune, Georges Hirtz, Guy de Maupassant, Victor Hugo et bien d’autres.\r\n– Des analyses de Roger Vétillard sur l’insurrection de mai 1945 à Sétif, sur celle du 20 août 1955 dans le Constantinois et sur le massacre de Palestro.\r\n– Une critique des \"apôtres de la décolonisation\" Frantz Fanon, Jean-Paul Sartre, Simone de Beauvoir et Albert Memmi.\r\n– Des croquis supplémentaires de Jacques Ferrandez, différents tableaux, cartes et esquisses et de nombreux témoignages sur la vie en Algérie.\r\n– Des informations sur les Hauts-Plateaux et Trézel.\r\n– Une analyse sur le rôle des instituteurs et des manuels scolaires en Algérie, etc.\r\n\r\nDate de parution : 26 mars 2014\r\n\r\nFormat : 20 cm x 30 cm (A4)\r\n\r\n198 pages, dont 40 en couleur\r\n\r\nPoids : 840g\r\n\r\nPour commander, envoyer un courriel à\r\n\r\neditions.atlantis@orange.fr\r\n\r\nou\r\n\r\n<b>commande@editionatlantis.de</b>\r\n\r\nou\r\n\r\n<b>bestellung@editionatlantis.de</b>\r\n\r\nKostenloser Versand für Bestellungen innerhalb Deutschlands.\r\n\r\nBitte setzen Sie sich vor einer Bestellung auf unserer Internetseite kurz mit uns in Verbindung, oder bestellen Sie über den deutschen Buchhandel (ohne Versandkosten) bzw. auf amazon.de (Versandkosten 2 € 99).', 28, '978-3-932711-70-1', 1),
(48, 1, 0, 'Douze fables en sabir. Avec le CD du disque original', '<b>Préface de Maurice Calmein.\r\nPrésentation et analyse de Fernand Arnaudiès.</b>\r\n\r\n<i>Ces fables en sabir, dont le CD ci-joint a été tiré et qui sont d\'ailleurs faites pour être lues à haute voix (d\'où leur écriture phonétique), révèlent l\'esprit pétillant et les différentes facettes de la personnalité de Charles Galléa: attachement à son pays natal, goût du détail pittoresque, musique des mots et de l’accent, humour, sensibilité, poésie enfin, sans laquelle ces fables n’auraient pas eu la même dimension littéraire.\r\nChacune d’entre elles est à la fois un tableau, un bouquet de couleurs vives, un morceau choisi où les mots et les sonorités s’entremêlent, mais aussi un moment d’émotion, de complicité dans les sentiments les plus simples. </i>\r\n\r\nEnfin, et ce n’est pas là leur moindre intérêt, ces textes sont le symbole de l\'intégration qui s\'opérait entre les communautés dans une Algérie aujourd\'hui disparue.\r\n\r\nLes fables de Charles Galléa témoignent, à leur façon, pour l\'histoire et il serait regrettable de n\'en retenir que le côté plaisant. Savourons-les donc sans modération, en ayant à l\'esprit qu\'elles sont avant tout le reflet d’une grande aventure humaine, l’écume d\'une profonde mêlée d\'âmes. (Maurice Calmein)\r\n\r\nCollection France-Algérie 39\r\n\r\n60 pages + 1 CD', 17, '978-3-932711-39-8', 1),
(49, 1, 0, 'Le soleil colonial. Au Royaume des cailloux', 'Cette petite saga est une suite indépendante de <i>L’Odyssée de Grain de Bled en terre d’Ifriqiya</i> (2013), où l\'auteur a suivi les pérégrinations de <i>Grain de Bled</i> à travers le temps et l’espace de l’Afrique du Nord dans le but de venir s’incarner dans une petite fille, Marie Sahara, dont il est l’âme.\r\nÉchappés in extremis à la tuerie du 5 juillet 1962 à Oran, les derniers membres de la famille, le cœur brisé, doivent quitter définitivement leur patrie algérienne.\r\n\r\nCe livre se veut aussi un hommage à la fraternité qui régnait en Algérie, fait oublié de l’histoire officielle.\r\nEt comment ne pas rapprocher ce \"soleil colonial\" du livre de Ferhat Abbas : <i>La Nuit coloniale</i> ?\r\nDeux visions d\'une même histoire qui n\'est jamais ni toute blanche ni toute noire…\r\n\r\n<i>\"Moi qui suis petite-fille et fille de colons, fière de leur travail, j’ai voulu témoigner de la grandeur de ces femmes et de ces hommes que j’ai vus à la peine pendant toute leur vie pour fertiliser une terre sauvage et hostile.\r\nIls sont devenus seigneurs – mais d\'un royaume de cailloux qu’ils ont passionnément aimé.\"</i>\r\nMaïa Alonso est l’enfant de la quatrième génération d’une famille espagnole arrivée d’Arboleas pendant l’été 1870, pour s’établir dans le Sud oranais, dans la région de Mascara.\r\n\r\n<b>Prix \"Terre d\'Eghriss\" 2014</b>\r\n\r\nCollection France–Algérie 40\r\n\r\n<b>Voici une lettre à l\'auteur (octobre 2014) :</b>\r\n\r\nBonjour Maïa,\r\n\r\nJe n\'ai pas lu votre livre : je l\'ai dévoré, en à peine plus d\'une journée !\r\n\r\nIl est actuellement entre les mains de mon mari (de la minorité rare des Patos qui nous comprenaient), puis il passera entre celles de nos fils ; je veux qu\'ils essaient de comprendre ce qu\'a été notre (courte) jeunesse là -bas…\r\nVous et moi n\'avons pas les mêmes racines, n\'avons pas eu la même enfance, mais avons vécu les mêmes émotions, qu\'on retrouve aux quatre coins du livre ! Je suis le fruit d\'un mélange de régions française et italienne par mes grands-parents, fille et petite-fille d\'instituteurs qui ont œuvré en bonne partie dans le bled . J\'habitais Oran mais j\'ai le souvenir encore vivace de peurs, de paquets à contourner dans la rue, d\'explosions.\r\nJe n\'ai pas pu me retenir de rire à l\'évocation des deux robes l\'une sur l\'autre au départ (pour moi, c\'étaient deux jupes). Revécu aussi le terrible moment du choix à faire pour n\'emporter qu\'une seule de mes poupées ...\r\nJ\'ai aussi vibré à votre \"Putain de pays !\" En débarquant devant la gare Matabiau, avec ma sœur et mes grands-parents (j\'avais l\'âge de Marie, le vôtre…) j\'ai pensé : \"Les Français sont fous !\" C\'était un jour de finale de rugby, déchaînement de \"folie\", de joie, si loin de nous et de notre désarroi.\r\nLe temps a passé, tout est enfermé dans une grande marmite, mais elle bout en permanence et il suffit de soulever un peu le couvercle pour que tout saute à la figure avec une émotion intacte !\r\n\r\nMichel S. m\'avait conseillé de ne pas aller jusqu\'au bout, pensant la fin trop dure pour ma sensibilité; mais j\'avais déjà lu bien pire sur cette journée du 5 juillet 1962. Vous avez très bien fait de ne pas l\'éviter !\r\n(Pour votre info, je vous signale que -pour la toute première fois- le nouveau programme d\'histoire des Terminales consacre une page entière au \"devoir de mémoire des Pieds-Noirs\", une autre sur \"Le 5 juillet 1962 à Oran\" : enfin ! )\r\n\r\nUn grand merci à vous pour ce livre à la fois roman, témoin, souvenirs, thérapie...\r\n\r\nAvec toutes mes amitiés,\r\nColette N.\r\n\r\nRecensions :\r\n\r\nhttp://www.ladepeche.fr/article/2014/06/16/1901354-l-algerie-le-terroir-du-soleil-colonial-de-maia-alonso.html', 22, '978-3-932711-40-4', 1),
(50, 1, 0, 'Dis, c\'était comment, au temps de l\'Algérie française ? 20 questions et réponses à  l\'intention des jeunes Pieds-Noirs. Avec des illustrations de Jean Brune', 'Ce livre n\'a d\'autre ambition que d\'aider à rétablir quelques vérités bafouées et à lutter contre la désinformation qui entoure depuis plus de 50 ans l\'histoire de l\'Algérie française. Il est plus particulièrement destiné aux jeunes générations des familles françaises qui ont dû quitter l\'Algérie au moment de son indépendance en 1962. Sa présentation sous forme de questions et réponses en rend la lecture plus facile et pratique.\r\nMais ce livre n\'est pas pour autant un livre pour enfants car certains passages, et notamment quelques récits rapportés par des témoins d\'événements dramatiques, pourraient heurter leur sensibilité.\r\nIl pourra toutefois aider leurs parents à répondre aux principales questions qui pouirraient leur être posées et à contribuer ainsi à rendre justice à uen communauté et à une page d\'histoire trop souvent méconnues, incomprises et décriées.\r\nEnfin, ce livre constituera une approche sysnthétique pour toute personne désireuse de s\'informer sur ce que fut vraiment l\'oeuvre de la France en Algérie.\r\n\r\nNouvelle édition revue et augmentée de l\'édition de 2005.\r\n\r\n134 pages\r\n61 illustrations dont 17 en couleur.', 17, '978-3-932711-41-1', 1),
(51, 1, 0, 'Les enfants de la Licorne', 'Dans l’Hérault des années 1970, une demeure ancestrale abritant un secret est vendue aux enchères à une mystérieuse Brésilienne. La famille expropriée s’installe dans le village. Chacun de ses membres va réagir à sa façon. Certains sont meurtris, voire anéantis, d’autres se rebellent. D’autres encore entrevoient une libération du joug des traditions.\r\n\r\nLa plus belliqueuse est Tiane, une adolescente de 15 ans, qui, pour récupérer le domaine, rêve de chevaucher la Licorne des contes de son aïeule et de pourfendre la Brésilienne, en qui elle voit la réincarnation de la Buse, référence à Simon de Montfort, ennemi mortel de ses ancêtres.\r\nMais des liens inattendus se tissent entre les protagonistes et vont bouleverser leurs destinées.\r\n\r\nUn roman où l’enfance, l’amour, la mort, l’histoire et les légendes se déclinent sur une terre souveraine.\r\nEt où le réel et le fantastique deviennent indiscernables…\r\n\r\nMaïa Alonso vit en Gascogne après une jeunesse nomade entre Mascara, Toulouse, Londres et Paris.\r\nElle a publié deux romans :\r\n\r\n<i>L’odyssée de Grain de Bled en terre d’Ifriqiya</i> (L\'Harmattan, 2013) et\r\n\r\n<i>Le soleil colonial – Au Royaume des cailloux </i>(Éditions Atlantis, 2014 ; Prix Terre d’Eghriss 2014).', 22, '978-3-932711-80-0', 1),
(52, 1, 0, 'Francaoui', 'Ce roman raconte la vie d’une famille « francaoui » au Maghreb, à l’apogée de la présence française, entre 1931 et 1954. Ce récit ordinaire qui évoque une époque extraordinaire renoue les fils entrecroisés par les parents et les enfants.\r\nUn fil, singulièrement, émerge du motif.\r\nIl est tissé par Guillaume qui naît sur le sol algérien et le quitte à 19 ans. Pour les autres, jeunes et vieux, l’Afrique du Nord n’aura été qu’un heureux séjour et la vie aura repris son cours normal avec leur retour en France.\r\nMais Guillaume sera marqué d’une empreinte secrète, celle de son Algérie à lui.\r\n\r\n<i>« Toi, tu es un Français de France », me disaient mes camarades, tant musulmans que français d’Algérie, alors que j’avais passé toute ma jeunesse parmi eux.\r\nIl a fallu plus de cinquante ans pour que je ressente le besoin d’exorciser cette singularité en une saga mêlant réalité et fiction, dans la vision d’un enfant au regard candide, puis naïf, enfin ingénu.</i>\r\n\r\nJérôme Tanon est né en 1935 à Paris.\r\nIl a vécu au Maroc, puis à Alger, jusqu’à l’âge de 19 ans. Après une longue carrière d’ingénieur dans l’industrie, il s’est installé dans le Midi.\r\n\r\nCollection France-Algérie 42\r\n\r\nRoman\r\n\r\n310 pages', 24, '978-3-932711-42-8', 1),
(53, 1, 0, 'Bab-el-Oued', '<b><i>Bab-el-Oued raconté à Toinet</i> (1955). <i>Alger – Bab-el-Oued</i> (1956). Avec des extraits de : <i>Cette haine qui ressemble à l\'amour</i> (1961) – <i>Journal d\'exil</i> (1963) – <i>Interdit aux chiens et aux Français</i> (1966)</b>\r\n\r\nSi Camus a chanté Belcourt, Brune s’est penché sur le quartier de Cagayous, Bab-el-Oued, ce melting pot fascinant.\r\nDans son roman <em>Cette haine qui ressemble à l\'amour</em> (1961) et son <em>Journal d\'exil</em> (1963), Brune a longuement déclaré son amour pour ce faubourg d\'Alger. Dans <em>Interdit aux chiens et aux Français</em> (1966), il a décrit son calvaire qui était celui de toute l\'Algérie française.\r\nMais déjà en 1955, dans une série d\'articles pour <i>La Dépêche quotidienne</i>, c’est plein de tendresse et d’humour que Brune a \"raconté Bab-el-Oued à Toinet\" en y ajoutant une cinquantaine de caricatures pertinentes.\r\n<strong>Tous ces écrits se trouvent réunis dans cette nouvelle édition.</strong>\r\n\r\n<strong>Écoutons Jean Brune :</strong>\r\n\r\n<em>\"Bab-el-Oued ?</em>\r\n<em>Ce n\'est pas une ville espagnole, ni italienne, ni française. C\'est une ville nouvelle… une ville comme il n\'en existe nulle part ailleurs.</em>\r\n<em>C\'est une ville-synthèse.</em>\r\n<em>Elle est née du brassage de tout ce que la Méditerranée compte de pèlerins de l\'aventure, dont les yeux sont accoutumés à chercher au-delà de l\'horizon de la mer d\'insaisissables eldorados.</em>\r\n<em>C\'étaient des Napolitains orgueilleux, des Maltais subtils, des Corses fiers comme des condottières, des Andalous nonchalants, des Calabrais têtus, des Catalans tragiques… et des Français plus sceptiques que toutes les races du monde puisqu\'ils sont capables de rire même des miracles qu\'ils accomplissent.</em>\r\n<em>Ils ont importé un prodigieux acharnement au travail et toutes les traditions latines qui comptent parmi les plus somptueuses du monde.</em>\r\n<em>Mais ils ont surtout apporté la gaieté et la jeunesse des races régénérées par les échanges… une vivacité que les bourgeois glacés et pincés jugent vulgaire mais qui n\'est qu\'une manifestation de la spontanéité des gens sincères et simples… la bonhommie familière des peuples qui ont trop souffert pour ne pas avoir appris les vertus de l\'indulgence… et qui savent dissimuler les soucis quotidiens derrière des plaisanteries et des rires qui sont la pudeur des gens pauvres.</em>\r\n<em>Voilà Bab-el-Oued.\"</em> (Jean Brune)\r\n\r\nAvec 50 illustrations et caricatures de Jean Brune.\r\n\r\nCollection France-Algérie 43\r\n\r\n<strong>Grand format : 20 x 30 cm</strong>\r\n\r\n88 pages / 350g', 19, '978-3-932711-43-5', 1),
(54, 1, 2, 'Les écrivains pieds-noirs face à la guerre d’Algérie (1954-1962). Albert Camus - Jean Brune - Roger Curel - Robert Merle - Janine Montupet - Marcel Moussy - Jean Pélégri - Emmanuel Roblès - André Rosfelder - Jules Roy', 'Préface de Maurice Calmein.\r\n\r\nLe 1<sup>er</sup> novembre 1954, la guerre d’Algérie commence par une série d’attentats. L’armée française riposte violemment au terrorisme du <i>Front de libération nationale</i> (F.L.N.) envers ses confrères musulmans et la population pied-noir.\r\n\r\nEn dépit de ses promesses et du succès militaire du « Plan Challe » en 1959 et 1960, Charles de Gaulle finit par abandonner l’Algérie. Le F.L.N. ne respectera pas les accords d’Evian : il enlèvera et tuera des milliers de Pieds-Noirs. Il ne leur reste plus que l’exode. Le destin des Harkis et des autres supplétifs musulmans est pire encore : plus de 100.000 d’entre eux seront massacrés par les « vainqueurs ».\r\nLa réaction des écrivains pieds-noirs face à la guerre d’Algérie a été loin d’être unanime. Dans leurs œuvres écrites entre 1955 et 1962, ils ont – selon leur tendance politique – pris différentes positions par rapport à ce conflit existentiel.\r\n\r\n404 pages\r\n\r\nCollection France-Algérie 19', 27, '978-3-932711-19-0', 1),
(55, 1, 5, 'C\'était l\'Algérie heureuse. 1915-1965. Nouvelle édition', '<em>Je veux d’abord parler du « bled » algérien, mon berceau, la terre où j’ai grandi entre 1915 et 1935.\r\nMais je voudrais évoquer aussi ma vie d’homme jusqu’en 1965, dans Alger, Alger-la-Blanche, qui demeure pour moi la plus belle ville du monde.\r\n</em>\r\n\r\n<em>Au total, j’aurai passé cinquante ans sur cette terre qui m’a vu naître. Un demi-siècle d’Algérie que je veux raconter pour laisser à mes enfants des racines profondes.</em>\r\n\r\n<em>Car ce sont les racines des hommes qui les empêchent d’être mortels. Nos souvenirs de jeunesse demeurent nos vraies richesses, notre plus bel héritage. Lorsqu’ils nous liront, «le soir à la chandelle», nos enfants ou les enfants de nos enfants diront peut-être en refermant ce livre : «C’était le temps de l’Algérie heureuse».</em>\r\nAuteur de près de deux cents publications médicales, professeur de maladies infectieuses et tropicales à Alger, puis à Dijon, Fernand Destaing a développé dans cette dernière ville une seconde activité de <em>Médecine et Histoire</em> qui s’est soldée par la création d’un module, d’une trentaine de publications et d’une vingtaine de thèses.\r\n\r\nSur ces mêmes thèmes - la souffrance, la maladie et la mort de personnages célèbres - il a écrit cinq livres:\r\n- <em>La Fin des hommes illustres</em> (Presses de la Cité, 1977)\r\n- <em>Ces maladies qui ont changé le monde</em> (Presses de la Cité, 1978)\r\n- <em>La Souffrance et le Génie</em> (Presses de la Cité, 1980) (Prix Littré 1981)\r\n- <em>Le Pouvoir et la Folie</em> (Buchet-Chastel, 1993)\r\n- <em>Le Crépuscule des Princes</em> (Buchet-Chastel, 1995)', 22, '978-3-932711-44-2', 1),
(56, 1, 32, 'Fernand Destaing. Médecin de l\'histoire. Biographie', 'Cette biographie de <strong>Fernand Destaing</strong> (1915-2014), médecin de l’histoire comme il aimait se qualifier, est le résultat de nombreux entretiens menés par Benoît Gaumer au cours des deux dernières années de vie de son confrère, enrichie de ses mémoires <em>C’était l’Algérie heureuse</em> (éd. Atlantis 2000, ²2015).\r\nElle retrace le parcours exemplaire d’un médecin français d’Algérie, issu de la Faculté de médecine d’Alger, puis professeur dans celle-ci, avant de poursuivre son itinéraire professionnel à la Faculté de médecine de Dijon et surtout de donner libre cours à son imagination créatrice et son talent d’historien médecin.\r\nLa seconde partie du livre décrit le parcours de René Bourgeon (1912-1996), autre médecin français d’Algérie qui contribua à créer la Faculté de médecine de Nice.\r\nDans une troisième partie, toute l’œuvre de Fernand Destaing est présentée et analysée, invitant le lecteur à une exploration de ses principaux titres et à en (re)découvrir les qualités littéraires et historiques.\r\nCollection France-Algérie 45', 17, '978-3-932711-45-9', 1),
(57, 1, 33, 'Dictionnaire amoureux, gourmand et nostalgique de l\'Algérie française', '<strong>Invitation au voyage…</strong>\r\n\r\nJe vous invite à partager ces <em>mounas</em> qui sortent du four. Leur parfum incomparable vous accompagnera dans une bala­de en Algérie française, à travers un dédale de mots d\'origine française, espagnole, italienne, maltaise, arabe…\r\n\r\nVous pourrez alors retrouver – ou découvrir – les liens charnels qui unissaient les Pieds-Noirs à cette Algérie, à laquelle ils ont tant apporté et qui leur a tant donné en retour.\r\n\r\nCette Algérie qui est restée à jamais dans leur cœur, malgré les souffrances de la rupture et de l\'exil.\r\n\r\n368 pages - 30 illustrations - 660g\r\n\r\nParu le 23 octobre 2015.', 25, '978-3-932711-47-3', 1),
(58, 8, 34, 'Sonnensprossen. Fünfzehn etwas andere Liebesgeschichten aus der Provence', '<strong><span style=\"font-size: 12pt;\">Fünfzehn \"etwas andere\" Liebesgeschichten…</span></strong>\r\n\r\n<span style=\"font-size: 10pt;\">Ob in den verträumten Dörfern des Vaucluse, auf einem Wein­gut in der Drôme provençale, bei einem Rundgang in Vaison-la-Romai­ne, im Château d\'If vor Marseille, auf der Halbinsel von Giens oder über den Dächern von Menton…</span>\r\n\r\n<span style=\"font-size: 10pt;\">Ob mit einer \"guten Freundin\", mit der Besitzerin einer kleinen Katze (oder einer alten Klapperkiste), am Rande einer Hoch­zeit, bei einem unverhofften Wiedersehen…</span>\r\n\r\n<span style=\"font-size: 10pt;\">Ob an der Kasse eines <em>Hypermarché</em>, beim Zusammenstoß mit einer Postbotin, an der Tür einer <em>Boulangerie-Pâtisserie</em>, beim Verkauf eines Autos oder sogar bei einer Zahnärztin: </span>\r\n\r\n<span style=\"font-size: 10pt;\">Stets funkt es ganz gewaltig zwischen den \"etwas anderen\" Erzäh­lern und den \"etwas anderen\" Frauen in diesen amüsanten, verspielten und reichlich \"verrückten\" Liebesgeschichten. </span>', 22, '978-3-932711-52-7', 1),
(59, 1, 35, 'Alger. Mes îles aux mouettes', '<strong>J\'ai écrit ce mémoire pour deux raisons très simples. </strong>\r\n\r\n<strong>La première afin d\'assouvir le besoin de revivre en quelque sorte les années de mon enfance et de mon adolescence dans un pays que j\'ai beaucoup aimé. Après des années de mouvance à travers le monde dues aux exigences professionnelles de mon époux, j\'ai eu besoin de retrouver mes racines.</strong>\r\n\r\n<strong>La seconde raison est celle du désir d\'une transmission de mémoire: faire connaître la vie des Français d\'Algérie à l\'époque de la présence française à travers les personnes que j\'ai connues, amis et membres de ma famille. Mais également évoquer les années de guerre jusqu\'à notre départ définitif.</strong>\r\n\r\n<strong>Avec 77 aquarelles, croquis et photos de l\'auteur.\r\n</strong>\r\n\r\n<strong>Grand format 30 x 20 cm.</strong>\r\n\r\n<strong>82 pages dont 36 en couleur</strong>.', 24, '978-3-932711-46-6', 1),
(60, 1, 30, 'Le papillon ensablé. Roman', '<strong>28 mai 1977, Hossegor :\r\nMaïsée,</strong><strong> jeune femme fragile psychologique­ment depuis son enfance algérien­ne, disparaît mystérieusement, laissant sa sœur Hélène et son mari Adrien, un ancien baroudeur, dans un profond désarroi.\r\nL’une dans l’île de Noirmou­tier, l’autre dans les hautes terres de l’Hérault, ils s’en­fer­­ment dans le passé et les regrets. </strong>\r\n\r\n<strong>En novembre 2007 survient l\'Algérien Rachid qui les </strong><strong>entraî­ne dans un douar fantôme au pied de la <em>Montagne</em> <em>qui chante</em> où, durant trente ans, une autre vie s’est déroulée, peuplée de personnages baroques : </strong>\r\n\r\n<strong>Karima, la meurtrière, Majdala, la fière Berbè­re, Ali, l’in­no­­­cent,  Baba Antoine, l’intégriste, Qura, la voix de</strong> <strong>la <em>Montagne</em>, et d’autres encore. </strong>\r\n\r\n<strong>Un roman traversé d’amours inavoués et difficiles, où</strong> <strong><em>\"cha­que jour est une victoire\".</em></strong>\r\n\r\n&nbsp;\r\n\r\n<strong>Maïa Alonso vit en Gascogne après une</strong><strong> jeunes­­se nomade entre Mascara, Toulou­se, </strong><strong>Lon­dres et Paris.\r\nElle a publié trois romans</strong><strong> :\r\n<em>L’odyssée de Grain de Bled en terre d’Ifriqiya</em></strong> <strong>(L’Harmattan, 2013), <em>Le soleil colonial –</em></strong><strong><em> Au Ro­yaume des cailloux </em></strong><strong>(Atlantis, 2014 ; Prix</strong> <strong>Terre d’Eghriss 2014) et <em>Les enfants de la </em></strong><strong><em>Licor­ne </em></strong><strong>(At­lan­tis, 2015).</strong>\r\n\r\n<strong>Roman - 232 pages</strong>\r\n\r\n<strong>Collection France-Algérie 49</strong>\r\n\r\n&nbsp;', 22, '978-3-932711-49-7', 1),
(61, 9, 36, 'Kirchenführer Ostallgäu und Kaufbeuren', 'Es gibt im Ostallgäu eine verblüffend große Zahl sehenswerter Kirchen und Kapellen. Zum ersten Mal werden hier die wichtigsten und reizvollsten von ihnen vorgestellt, die den Vergleich mit den Schmuckstücken des Pfaffenwinkels in keiner Weise scheuen müssen.\r\n\r\nÜber<strong> 600 Abbildungen –</strong> durchweg eigene Fotos des Autors – ergänzen die <strong>114 Beschreibungen</strong>, die auch für den Laien verständlich und dabei doch wissenschaftlich korrekt sind.\r\n\r\nIm Anhang erhält der Leser in mehr als <strong>70</strong> <strong>Kurzbiographien</strong> Auskunft über die bedeutendsten einheimischen und auswärtigen Künstler, die in den beschriebenen Kirchen tätig waren.\r\n\r\nDer Autor,<strong> Herbert Wittmann</strong> (geb. 1935) ist im Allgäu aufgewachsen und wohnt seit 1974 in Biessenhofen. Als Mathematik- und Physiklehrer war er 39 Jahre lang im Schuldienst tätig und ging 1998 als Leiter der Realschule Marktoberdorf in den Ruhestand. Seitdem kann sich der passionierte Fotograf – mit 14 erstand er seine erste Kamera – endlich ganz seinem Steckenpferd widmen: das Leben und Werk einheimischer Bildhauer zu erforschen. Zahlreiche Publikationen (u. a. <em>Allgäuer Zeitung</em>, <em>Das schöne Allgäu</em>, <em>Alt Füssen</em>, <em>Extra Verren</em>, <em>Landsberger Geschichtsblätter</em>) zeugen von seinem starken Engagement für die lokale Kunst­geschichte.\r\n\r\nSiehe auch seine beiden anderen Werke, die ebenfalls in unserem Verlag erschienen sind.', 34.9, '9783932711558', 1),
(62, 1, 37, 'La mort mystérieuse du colonel Halpert le 15 février 1946 à Constantine. Enquête historique', 'Le 15 février 1946, le colonel Émile Halpert, commissaire du gouvernement près du Tribu­nal militaire de Constantine chargé de juger les insurgés de l’insurrection du 8 mai 1945 dans le Nord-Constantinois, a une entrevue orageuse avec André Le Troquer, ministre de l’Intérieur.\r\n\r\nLe soir, Émile Halpert est retrouvé sans vie dans sa chambre d\'hôtel : il se serait suicidé. À l\'époque, sa mort a été plus ou moins occultée et n’a donné lieu ni à de longs développements journalistiques, ni à des études historiques ultérieures : était-ce un assassinat ou un suicide ?\r\n\r\nL’auteur, qui a découvert ces faits lors de ses recherches sur les événements de 1945 en Algérie, a repris en détail la vie et la carrière du magistrat, analysé le contexte familial, histori­que, juridique, politique et psychologique, pour nous livrer ses conclusions. Lors de cette véritable enquête policière, de nom­breuses questions sont évoquées, des certitudes apparaissent, des interrogations demeurent.\r\n\r\n92 pages - 15 €\r\n\r\nISBN 9783932711565', 15, '9783932711565', 1),
(63, 1, 30, 'Le rêve assassiné. Roman vrai', '<span style=\"font-size: 14pt; color: #0000ff;\"><strong>Cet ouvrage a reçu le Prix 2017 de la <em>Fondation pour la Mémoire de la Guerre d\'Algérie, des combats du Maroc et de Tunisie. </em></strong></span>\r\n\r\n<span style=\"font-size: 14pt; color: #ff0000;\"><strong><span style=\"color: #0000ff;\">La cérémonie a eu lieu le 19 octobre 2017 à Paris.</span>\r\n</strong></span>\r\n\r\n<strong>Dans la nuit du 8 avril 1958, en rentrant à leur ferme, Félix Vallat, maire de Thiersville, et son épouse Madeleine, institutrice, furent sauvagement assassinés par un commando terroriste du FLN. Miraculeusement, leurs trois fils survécurent.</strong>\r\n\r\n<strong>Cette nuit-là, ce n\'était ni l’ingénieur agricole, ni l\'ancien pilote RAF, ni l’animateur hors pair qui était visé. </strong>\r\n\r\n<strong>Non, c\'était tout simplement ce véritable apôtre du rapprochement franco-musulman qui dérangeait les nationalistes algériens et qu’il fallait donc éliminer avec toute sa famille. </strong>\r\n\r\n<strong>Avec eux, ils ont assassiné le rêve d\'une Algérie nouvelle, une Algérie autonome et fraternelle, multiethnique et tolérante, liée étroitement à la France : l\'Algérie dont rêvait aussi Albert Camus.</strong>\r\n\r\n&nbsp;\r\n\r\n<strong>Maïa Alonso nous livre ici le roman vrai de la vie des époux Vallat :\r\n</strong>\r\n\r\n<strong><em>« Je veux faire entendre la voix de tous les acteurs de ce drame – même celle du commanditaire de cet odieux assassinat, l\'un des proches amis musulmans de Félix Vallat. Et si la terreur du FLN est montrée du doigt, la vengeance à laquelle certains, désespérés, se sont livrés par la suite n\'est pas moins occultée. »</em></strong>\r\n\r\n<strong>Ce roman est d\'une actualité brûlante :\r\nla cohabitation pacifique en terre d\'Islam restera-t-elle toujours un rêve ?</strong>\r\n\r\n<strong>Maïa Alonso a déjà publié quatre romans : </strong>\r\n\r\n<strong><em>L’odyssée de Grain de Bled en terre d’Ifriqiya</em></strong><strong> (2013), <em>Le soleil colonial </em>(2014), <em>Les enfants de la Licorne</em> (2015) et <em>Le papillon ensablé </em>(2016).</strong>\r\n\r\n254 pages - avec une documentation et une cinquantaine d\'illustrations\r\n\r\n&nbsp;', 22, '9783932711480', 1),
(64, 9, 36, 'Peter Heel. Der vornehme Bildhauer von Pfronten (1696-1767)', '<strong>Peter Heel, der geniale Sohn Pfrontens</strong>\r\n\r\nDie professionelle Kunstforschung hat sich bisher nur wenig oder überhaupt nicht mit <strong>Peter Heel</strong> (1696-1767) beschäftigt, dem großen, ja genialen Sohn Pfrontens und nach <strong>Peter Volk</strong> \"bedeutendsten Rokokobildhauer der Region. Es ist deshalb eine verpflichtende Aufgabe, Peter Heel endlich in seinem 250. Todesjahr die ihm zustehende Anerkennung und Ehre zukommen zu lassen.\r\n\r\nHerbert Wittmann hat sich vor fast 30 Jahren auf die Suche nach den bislang unbekannten Werken Peter Heels gemacht. Auch wenn viele Arbeiten – vor allem jene aus der frühen Schaffensperiode – immer noch unauffindbar bleiben, so ist die Ausbeute seiner unermüdlichen und oft mühsamen Nach­forschungen doch beeindruckend: Nicht nur in <strong>über</strong> <strong>30 Orten im Ost- und Oberallgäu</strong>, sondern auch in anderen Teilen Schwa­bens, ja sogar in <strong>Ober- und Niederbayern</strong>, in <strong>Baden-Württem­</strong><strong>berg </strong>und im <strong>Tiroler Außerfern</strong> wurde er fündig (siehe die rot markierten Orte <strong>?</strong><strong>?</strong>in der Karte unten).\r\n\r\nMit fast kriminalistischem Spürsinn, akribischer Genauigkeit und immensem künstlerischen Wissen zeigt er an jedem neuen Kunstwerk die kennzeichnenden <strong>Stilmerkmale</strong> des Pfrontener Bildhauers auf. Dass Peter Heel seine Kunst auch in den unterschiedlichsten <strong>Werkgemeinschaften</strong> ausübte, ist eine weitere Erkenntnis des Autors. So hat Peter Heel oft mit seinem Halbbruder, dem Maler <strong>Johann Heel</strong>, wie auch mit den Baumeistern <strong>Johann Georg Fischer</strong> und <strong>Franz Kleinhans</strong> zusammengearbeitet. Aber auch mit so berühmten Künstlern wie <strong>Joseph Anton Feuchtmayer</strong>, <strong>Diego Fran­cesco Carlone</strong> und <strong>Cosmas Damian Asam</strong> war er gemeinsam in Gotteshäusern tätig.\r\n\r\nHerbert Wittmann ist im Allgäu aufgewachsen und wohnt seit 1974 in Biessenhofen. Zahlreiche Publikationen – zuletzt der <em>Kirchenführer Ostallgäu und Kauf­­beuren</em> (2016) – zeugen von seinem großen Engagement für die loka­le Kunstgeschichte.\r\nIm August 1988 wurde für ihn die Begegnung mit Heels Figuren in der Pfarrkirche von Schöllang (bei Oberstdorf) zum Schlüsselerlebnis: \"Beim Anblick der hl. Barbara und der hl. Katharina am Hoch­­altar war es dann sozusagen um mich geschehen\", schreibt er rückblickend<strong>. </strong>\r\n\r\n170 Seiten - zahlreiche Abbildungen - erschienen am 29. April 2017.', 32.9, '9783932711572', 1);
INSERT INTO `publikationen` (`pub_id`, `kat_id`, `aut_id`, `titel`, `text`, `preis`, `isbn`, `available`) VALUES
(65, 6, 2, 'L\'Hôte. Albert Camus\' Novelle. Jacques Ferrandez\' ', '<span style=\"color: #ff0000;\"><strong>Kostenloser Versand:</strong></span>\r\n\r\n<span style=\"color: #ff0000;\"><strong>Bei Bestellung auf Rechnung über <span style=\"color: #0000ff;\">contact@editionatlantis.de</span> ist der Versand kostenlos.</strong></span>\r\n\r\n<strong>Zum Ziel dieser Handreichung:</strong>\r\n\r\nUnsere Absicht ist es, Lehrenden wie Lernenden fundierte, kompakte, methodisch abwechslungsreiche Materialien zur Erschließung der Novelle <em>L\'Hôte</em> an die Hand zu geben.\r\n\r\nNachgezeichnete BD-Vignetten ermöglichen eine visuell reizvolle Bearbeitung der zentralen Themen: So werden die Fehler und fragwürdigen Leerstellen in der BD ebenso wie deren grandiose Leistungen für die Interpretation der Novelle nutzbar gemacht.\r\n\r\nZusätzlich werden Textvarianten früherer Versionen der Novelle (sie entstand zwischen 1952 und 1957) als Hilfestellung eingebunden und dadurch die Schüler mit textkritischen Verfahrensweisen vertraut gemacht.\r\n\r\n&nbsp;\r\n\r\n<strong>Eine multimediale DVD:</strong>\r\n\r\nAuf der DVD finden sich <strong>alle Arbeits- und Ergebnisblätter</strong> sowie <strong>zahlreiche Ergänzungstexte </strong>(und natürlich auch die jeweiligen transkribierten Texte der Filmausschnitte) als <strong>PDF- und WORD-Dateien</strong>.\r\n\r\nAuszüge aus zwei Dokumentationen des Cinéasten Jean-Pierre Lledo (<em>Algérie, histoires à ne pas dire...</em> und <em>Grand-Père a tué deux \'colons\'</em>) beleuchten das von den algerischen Nationalisten organisierte Massaker von El Halia (Philippeville) am 20.8.1955 an der europäischen Zivilbevölkerung sowie den gescheiterten Aufstand vom 8.  Mai 1945 im Nord-Constantinois, auf den in der Novelle angespielt wird, obwohl deren Handlung (den Angaben im Novellentext zufolge) 1946 angesiedelt ist.\r\n\r\nMehrere Sequenzen aus <em>Les Oliviers de la Justice</em> (von James Blue und Jean Pélégri, 1962, nach dem gleichnamigen, bei Gallimard 1959 erschienenen Roman von Jean Pélégri), dem einzigen Spielfilm, der im Algerienkrieg 1961/1962 an Originalschauplätzen (Alger, Sidi-Moussa) gedreht wurde, stellen weitere einzigartige authentische Zeugnisse dar.\r\n\r\n&nbsp;\r\n\r\n<strong>Das sozio-kulturelle Spannungsfeld von <em>L\'Hôte</em>:</strong>\r\n\r\nZusätzlich wird das sozio-kulturelle und politische Spannungsfeld der <em>Algérie française</em> aufgezeigt, da nur dessen genaue Kenntnis eine adäquate, textnahe Deutung der Novelle - abseits von haltlosen oder gar vom Erzähler explizit dementierten Spekulationen und Phantastereien - erlaubt.\r\n\r\nDiese Informationen sind nicht nur als Wissens- und Kompetenzerweiterung für Lehrkräfte &amp; Schüler, sondern auch als Grundlage für Fach- und Seminararbeiten gedacht, für die ein eigener Themenkatalog mit Bearbeitungsvorschlägen angeboten wird.\r\n\r\nDiese Handreichung wie auch die bereits 2014 erschienene Studie zum kolonialen Kontext der Novelle (Wolf Albes: <em>\"L\'Hôte\". La nouvelle d\'Albert Camus et la bande dessinée de Jacques Ferrandez dans le contexte colonial</em>, Edition Atlantis) geben dem Leser umfangreiche authentische Materialien und Analysen an die Hand.\r\n\r\n&nbsp;\r\n\r\n<strong>Aus dem Inhalt:</strong>\r\n\r\n- Novelle contra BD: kritischer Vergleich auf 11 Farbseiten;\r\n\r\n- die Tragödienstruktur der Novelle; 2 Farbseiten (Novellen- und BD-Struktur);\r\n\r\n- 12 multifunktionale, methodisch vielfältig einsetzbare (illustrierte) Arbeitsblätter mit ausführlichen Lösungsvorschlägen;\r\n\r\n- über ein Dutzend illustrierter Lernzielkontrollen mit Varianten und umfangreichem Erwartungshorizont;\r\n\r\n- ergänzende Zeichnungen von Jacques Ferrandez und Impulse zur Erarbeitung von Ergänzungsvorschlägen zur BD;\r\n\r\n- <em>\"Cherchez l\'erreur\"</em> zu zentralen Themen und Aspekten;\r\n\r\n- weitere hilfreiche Materialien, u. a.:\r\n\r\na) Transkriptionen der 25 Filmsequenzen mit Erläuterungen;\r\n\r\nb) thematische Kurzanalysen, <em>résumés</em>, <em>commentaires</em>;\r\n\r\nc) Worterklärungen (chronologisch + alphabetisch)\r\n\r\nd) Grammatikübungen zu <em>gérondif/participe présent </em>u.a.m.\r\n\r\n120 Seiten.\r\n\r\n<span style=\"color: #ff0000;\"><strong>Kostenloser Versand:</strong></span>\r\n\r\n<span style=\"color: #ff0000;\"><strong>Bei Bestellung auf Rechnung über <span style=\"color: #0000ff;\">contact@editionatlantis.de</span> ist der Versand kostenlos.</strong></span>\r\n\r\n&nbsp;', 22, '9783932711718', 1),
(66, 7, 39, 'Die frühe Geschichte der Stadt Füssen', 'Füssen, die Stadt, die den Übergang über die Alpen vom deutschen in den italienischen Teil des Reichs beherrschte, gewann durch die Führungsrolle der Römer und später der Germanen in der europäischen Geschichte mehr Bedeutung als manche Großstadt.\r\n\r\nAber die Ansiedlung mit einem vermutlich aus dem Rätischen stammenden Namen und dem sizilianischen Wappen ist viel älter als das von den Römern gegründete Reich. Viele frühere Verkehrswege, Kultplätze und sogar ein heiliger Berg, der Säuling, bestätigen das.\r\n\r\nWährend bisher die Geschichte Füssens fast durchweg aus dem engen Blickwinkel \"lateinkundiger Schullehrer\" geschrieben wurde, bezieht der Autor bei seinem Neuansatz nicht nur technologische und klimatologische, sondern auch volkswirtschaftliche und soziale Aspekte mit ein.\r\n\r\nEr berücksichtigt dabei auch Erfindungen und Prozesse in weit entfernt gelegenen Gebieten wie dem Heiligen Land, Spanien, Italien aber auch nördlichen Gefilden, die für die Entwicklung dieses frühen Verkehrsknotenpunkts von erheblicher Bedeutung waren.\r\n\r\nIm Verlauf seiner akribischen Recherchen und fachkundigen Analysen kommt P. A. Bletschacher immer wieder zu faszinierenden Thesen, die viele bisherige Theorien in einem fragwürdigen Licht erscheinen lassen.\r\n\r\nSo nimmt die Via Claudia bei ihm in einigen Streckenabschnitten einen neuen Verlauf, und die Gipfel der umliegenden Berge formieren sich zu einem \"Allgäuer Stonehenge\".\r\n\r\nNicht nur der Einfluss früherer Religionen rückt in den Blick des Lesers, sondern auch ein ganz anderer Volksstamm, der bisher kaum Erwähnung fand: die Räter.\r\n\r\nSchließlich zeigt der Autor auf, wie der Geigenbau in Füssen entstand – und eben nur hier entstehen konnte.', 32.9, '9783932711589', 1),
(67, 1, 37, 'La dimension religieuse de la guerre d\'Algérie (1954-1962).  Prémices et conséquences. Préface de Gregor Mathias', '<strong>L\'arabo-islamisme dans la guerre d\'Algérie</strong>\r\n\r\nLa guerre d’Algérie (1954-1962) a revêtu une dimension religieuse qui a été manifestement négligée ou même ignorée par les historiens de tous bords qui ont choisi de l\'étudier à l’aune d’une vision anticolonialiste ou anticommuniste.\r\n\r\nEt pourtant, le 1<sup>er</sup> novembre 1954, le <em>Front de libération nationale</em> (F.L.N.) ouvre les hostilités avec un objectif bien paradoxal : \"la restauration de l’État algérien souverain, démocratique et social dans le cadre des principes islamiques\".\r\n\r\nLe 20 août 1956, le congrès de la Soummam entérine ces contradictions fondamentales entre l\'unanimisme autoritaire de l\'islam et l\'individualisme foncier de la démocratie libérale.\r\n\r\nDe fait, le F.L.N. aura, tout au long de ce conflit, un double discours :\r\n<ul>\r\n 	<li>celui qui utilise l’arme de la religion, seul lien unificateur entre les musulmans algériens, pour les entraîner dans une véritable guerre sainte contre l\'occupant \"mécréant\" ;</li>\r\n 	<li>un autre, plus policé, volontiers socialisant, à destination des pays socialistes et des intellectuels de gauche qui semblent tous n’y avoir vu que du feu.</li>\r\n</ul>\r\nRoger Vétillard analyse les identités et les stratégies respectives des principaux acteurs qui ont réussi à la fois à imposer et à cacher leur vision islamique et panarabe de la future <em>Algérie algérienne</em> – et cela en marginalisant ou éliminant tous ceux qui lui ont été hostiles.\r\n\r\n190 pages, 58 illustrations\r\n\r\nSortie officielle en librairie (en France) le 10 septembre 2018.\r\n\r\nDéjà disponible sur notre site et dans les librairies en Allemagne.\r\n\r\nL\'envoi est gratuit jusqu\'au 31 juillet 2018.', 22, '9783932711596', 1),
(68, 9, 36, '153 Sakrale Kunstwerke im Detail. Ostallgäu und Kaufbeuren', '<strong>153</strong> <strong>Kunstwerke? </strong>\r\n\r\n<strong>Petrus zog aus dem See Genezareth mit seinem Netz 153 große Fische an Land, also \"sehr viele\". </strong>\r\n\r\n<strong> </strong><strong>Deshalb hat Herbert Wittmann eine annähernd</strong><strong> gleich große Zahl an Kunstwerken aus den Kirchen und Kapellen unserer Region \"gefischt\", um sie uns vorzustellen – wesentlich genauer noch als in seinem erfolgreichen <em>Kirchenführer Ostallgäu und Kaufbeuren</em>: von Bauten und Altären über Marienbilder, Kreuze und Monstranzen bis hin zu Stuhlwangen und Werken der Passionskunst.</strong>\r\n\r\n<strong>In diesem faszinierenden Bilder- und Lesebuch</strong><strong> nimmt er uns mit auf eine Reise voller verblüffender Entdeckungen. Seine über 500 brillanten Fotos machen \"Lust auf Kirche\", auf jene kostbaren Schätze unserer Allgäuer Heimat, die den Vergleich mit ihren oft berühmteren Artgenossen in anderen Gegenden keineswegs scheuen müssen.</strong>\r\n\r\n<strong>Denn alle hier beschriebenen Werke sind von</strong> <strong>kunsthistorischer Bedeutung. Meist gibt es zu ihnen eine lesenswerte Geschichte zu erzählen</strong><strong> oder theologische Hintergründe zu erläutern, um ihre \"Botschaft\" besser verstehen zu können. </strong>\r\n\r\n<strong>Seine Texte sind auch für \"blutige Laien\" verständlich. Sie geben Anstöße und laden den Betrachter zum Innehalten und Nachdenken ein. Auch um sich sein eigenes \"Bild vom Bild\" zu machen.</strong>\r\n\r\n&nbsp;\r\n\r\n&nbsp;', 34.9, '9783932711626', 1),
(69, 9, 40, 'Die St. Martinskirche zu Leutkirch. Urkirche des Nibelgaus', '<span style=\"font-size: 14pt;\"><strong>Auf den Spuren der Leutekirche im Nibelgau</strong></span>\r\n\r\n<strong>Eine verblüffende Entdeckung</strong>\r\nAls Erwin Münsch beim Aufräumen zwei Bücher seines Vaters aus der Zeit des 2. Weltkriegs entdeckt, ahnt er noch nicht, dass er darin eine verblüffende Entdeckung machen wird: alte, völlig unbekannte Fotos aus der Zeit vor 1940, auf denen die Leutekirche in neugotischer Ausstattung abgebildet ist.\r\n\r\n<strong>Die Urkirche des Nibelgaus auf dem ersten Leutkircher Wappen</strong>\r\nDieser Fund ist der Auftakt zu seinen Nachforschungen über die Geschichte der St. Martinskirche, bei denen er das erste Wappen der Stadt Leutkirch entdeckt, auf dem die Urkirche des Nibelgaus abgebildet ist.\r\n\r\n<strong>Die Urkirche entstand im Jahr 761</strong>\r\nMittels astronomischer Rechenprogramme und der Ausrichtung der heutigen Kirche kann der promovierte Diplomingenieur das Jahr ihrer Erbauung bestimmen: 761.\r\nNun wissen wir, wann die Urkirche gebaut wurde und wie sie einst aussah.\r\n\r\n<strong>Die Schenkung der St. Martinspfarrei an das Kloster Stams</strong>\r\nDoch auch einem weiteren Rätsel geht er nach:\r\nWarum verschenkte Kaiser Karl IV. die St. Martinspfarrei an das Kloster Stams?\r\nDas Ergebnis ist verblüffend:\r\nUm seine Kaiserwürde zu legitimieren war es für Karl IV. von allergrößter Bedeutung, in den Besitz der Reichskleinodien und insbesondere der legendären Heiligen Lanze zu gelangen, die im Kloster Stams aufbewahrt wurde. Und so kam es, dass sich am 7. September 1352 Karl IV. für deren Aushändigung bei den Mönchen von Stams bedankte, indem er ihnen die Patronatsrechte an der St. Martinspfarrei übertrug.\r\nDarüber hinaus geht der Autor auf zahlreiche andere geschichtliche und volkskundliche Aspekte ein, so u. a.:\r\n\r\n<strong>Der Gallusmarkt: der älteste städtische Markt Deutschlands</strong>\r\nDie Urkirche wurde nach dem Sonnenuntergang am Todestag des heiligen Gallus ausgerichtet, der für die Christianisierung des Allgäus und für Leutkirch eine besondere Bedeutung hatte. Es ist davon auszugehen, dass der Gallusmarkt am Gallustag schon von Anbeginn an stattfand: Leutkirch hat also mit 1250 Jahren die älteste städtische Markttradition in Deutschland.\r\n\r\n<strong>Das Rätsel des Nachtgugelers</strong>\r\nIn Oberschwaben und im Allgäu warnten früher die Mütter ihre Kinder, sie sollten am Abend nicht zu lange draußen bleiben, sonst hole sie der Nachtgugeler. Aufgrund mehrerer Hinweise stellte der Autor fest, dass es sich dabei um den genius cucullatus, einen zwerghaften keltischen Kapuzendämon handelte.\r\n\r\n<strong>Aus dem Inhalt:</strong>\r\n1. Die Zeit vor der Christianisierung\r\n2. Die Baugeschichte\r\n3. Das Innere der Kirche - die Kirchenschätze\r\n4. Eine Reichspfarrei wird verschenkt\r\n5. Die St. Martinskirche und die Reformation\r\n6. Die St. Martinspfarrei\r\n7. Die Pfarrer der St. Martinskirche\r\n8. Zeittafel\r\n9. Bibliographie\r\n\r\n&nbsp;\r\n\r\n<span style=\"color: #ff0000;\"><strong>Der (minimal veränderte) Nachdruck ist ab 10.03.2019 verfügbar/bestellbar. Vormerkungen über E-Mail (contact@editionatlantis.de) möglich.</strong></span>', 17, '9783932711619', 1),
(70, 1, 41, 'Voyage au bout de l\'Éden. Conte philosophique. Préface de Norbert Multeau', '<strong>\"Jean Taousson est un véritable écrivain. Il l’a prouvé avec </strong><em><strong>Adieu</strong></em> <em><strong>Roumi</strong></em><strong>, un récit de la guerre d’Algérie plein de révélations sur des épisodes que l’Histoire officielle oublie soigneusement de relater.</strong>\r\n\r\n<strong>Dans </strong><em><strong>Jacques Derrida, mes potes et moi</strong></em><strong>, il nous dresse le portrait d’un copain de football qui n’était autre que le fameux inventeur de la </strong><em><strong>déconstruction</strong></em><strong>, l’intellectuel le plus adulé et le plus controversé depuis le siècle des Lumières. Rien ne devait rapprocher ces deux</strong> <strong>Algérois, si ce n’est l’amour du ballon rond.</strong>\r\n\r\n<strong>Dans </strong><em><strong>Voyage au bout de l’Éden</strong></em><strong>, le héros, Guiscard Destin, meurt dans un accident de voiture. Mais ayant échappé à l’administration que dirige Saint Pierre à la porte du Paradis, il se promène sans visa à travers les siècles.</strong>\r\n\r\n<strong>Dans ce roman de science-fiction en forme de règlements de comptes depuis l’apparition de l’Homme sur terre, on joue à la pétanque avec Jésus-Christ et Yves Montand, on vit une brève idylle avec Jeanne d’Arc, on disserte avec Socrate, Diogène, Sir Arthur Conan Doyle ou Napoléon Bonaparte. On bat les plus grands champions de boxe et l’on relègue le général De Gaulle et sa clique dans une constellation lointaine. On défait les manœuvres des migrants qui veulent faire de la France un pays </strong><em><strong>hallal</strong></em><strong>. </strong>\r\n\r\n<strong>Jean Taousson nous livre un conte philosophique qui relève à la fois de Voltaire et des Marx Brothers. C\'est un chef-d’œuvre d’humour avec l’impolitesse du désespoir.\"    </strong><em><strong>Frédéric Musso</strong></em>\r\n\r\n<strong>Collection France-Algérie 52</strong>\r\n\r\n<strong>140 pages</strong>\r\n\r\n<strong>Prix : 17 €</strong>\r\n\r\n<span style=\"color: #ff0000;\"><strong>Paru le 8 mai 2019.</strong></span>', 17, '9783932711633', 1),
(71, 1, 41, 'Alger ma Blanche. 42 tableaux. Peinture naïve et aquarelles', '<strong><em>\"</em></strong><strong><em>Jeune rameur au Rowing Club, j\'ai parcouru le port d\'Alger en long et en large trois fois par semai­ne pendant quatre ans. Plus tard, reporter à l’Écho, j’ai arpenté ses quais quotidiennement, écouté battre le cœur du plus grand havre d’Afri­que du Nord pour raconter son his­toire dans la rubrique maritime de mon journal.\" </em></strong>\r\n\r\n(Jean Taousson, auteur du conte philosophique <em>Voyage au bout de l\'Éden</em>, Éd. Atlantis, 2019)\r\n\r\n<strong><em>\"Les années ont passé et je revois Alger ma Blan­che, des paysages. Je hume des parfums. Images, sons, odeurs se bousculent dans ce voyage à l’envers de ma mémoire.\"</em></strong>\r\n\r\n(Danielle Deliot-Libmann, <em>Alger. Mes îles aux mouettes</em>, Éd. Atlantis, 2016)\r\n\r\nGrand format (paysage) 30 cm x 21 cm : 90 pages avec 42 tableaux en couleur.\r\n\r\nPeinture naïve (Jean Taousson) et aquarelles (Danielle Deliot-Libmann).\r\n\r\nÀ paraître fin septembre 2019', 23, '978-3-932711-65-7 ', 1),
(72, 1, 41, 'Alger ma Blanche. Calendrier 2020 et 2021. 25 tableaux de Jean Taousson', '<span class=\"readonlyText multiple\">Calendrier pour 2020 et 2021 avec 25 tableaux de Jean Taousson (peinture naïve, en couleur).</span>\r\n\r\nFormat 30 cm x 21 cm (paysage).\r\n\r\n17 €', 17, '9783932711671', 1),
(73, 10, 36, 'Kirchenfresken. Ostallgäu und Kaufbeuren. Kalender 2020. Bilder von Herbert Wittmann', 'Bei der Auswahl der 13 Deckenfresken wurden personenreiche Schilderungen mit einem dramatischen Geschehen bevorzugt. Alle Kunstwerke sind in den angegebenen Kirchen zu besichtigen. In den meisten Fäl­len besteht ein Bezug zu einem Gedenktag oder Fest im jeweiligen Mo­nat. Sieben Fresken (1, 3, 4, 5, 7, 8, 11) sind in <strong>153.</strong> <strong>Sa­krale Kunst­werke</strong> ausführlicher be­schrieben. Alle Kalenderbilder sind auch im <strong>Kirchenführer Ost­allgäu und Kaufbeuren </strong>zu finden (bei­de Kunstbände von Herbert Wittmann).\r\n\r\nA3-Format (42 cm x 30 cm)', 19, '9783932711664', 1),
(74, 1, 2, 'La guerre d\'Algérie vue par six anciens combattants allemands de la Légion étrangère', 'Plusieurs anciens combattants de la Légion étrangère, tous de très jeunes Allemands qui s\'étaient engagés entre 1956 et 1959, se souviennent.\r\n\r\nWolf Albes a réuni et traduit les témoignages les plus intéressants et émouvants, publiés tous aux éditions Epee (Kehl am Rhein), pour les mettre à la disposition des historiens francophones.\r\n\r\nIl s\'agit de :\r\n\r\nWolf-R. <strong>Barthel </strong>: <em>Verdammt und geliebt. Erinnerungen eines Fremdenlegionärs</em>, Kehl am Rhein [Epee-Edition] ²2012\r\n\r\nEberhard <strong>Nadjé</strong>, Jürgen <strong>Bergner</strong>, Dieter <strong>Fessler</strong> : <em>Fremdenlegion in Algerien: 1956-1964</em><em>. Erinnerungen von Eberhard Nadjé, Jürgen Bergner, Dieter Fessler</em>, Kehl am Rhein [Epee Edition] 2014\r\n\r\nAlexander <strong>Stelzl</strong> : <em>Die Facetten der französischen Fremdenlegion. Vergangene und heutige Erlebnisse eines ehemaligen Legionärs</em>, Kehl am Rhein [Epee Edition] 2017\r\n\r\nVolker <strong>Lordick</strong> : <em>Légionnaire en Algérie : 1959-1964</em>, Kehl am Rhein [Epee Edition] 2013  (déjà traduit et édité en français)\r\n\r\n<span style=\"color: #ff0000;\"><strong>Texte disponible comme PDF  !</strong></span>\r\n\r\n<span style=\"color: #ff0000;\"><strong>Vous pouvez le télécharger gratuitement en cliquant sur le lien en bas de pa<span style=\"color: #ff0000;\">ge  (\"</span></strong><strong>Informations supplémentaires / Extraits\").</strong></span>\r\n\r\n<span class=\"option_input\"><a class=\"link\" href=\"http://editionatlantis.de/wordpress/wp-content/uploads/publinks/Wolf Albes - La guerre dAlgérie vue par six anciens combattants allemands de la Légion étrangère - 23 04 2020.pdf\" target=\"_blank\" rel=\"noopener\">http://editionatlantis.de/wordpress/wp-content/uploads/publinks/Wolf Albes - La guerre dAlgérie vue par six anciens combattants allemands de la Légion étrangère - 23 04 2020.pdf</a></span>', 0, '000', 1),
(75, 1, 37, 'La guerre d\'Algérie, une guerre sainte ?', '<strong>L\'arabo-islamisme dans la guerre d\'Algérie</strong>\r\n\r\n<strong>Préface de Guy Pervillé</strong>\r\n\r\n<strong>Deux ans après sa première étude sur la dimension religieuse de la guerre d’Algérie, Roger Vétillard revient sur ce sujet délicat, longtemps caché, négligé ou même ignoré par les historiens.</strong>\r\n\r\n<strong>   Grâce aux précieux retours de ses collègues et ses lecteurs et à la suite de ses recherches encore plus approfondies, il est en mesure de nous présenter une nouvelle étude encore plus vaste et pertinente, où il a mis à jour et amplement enrichi les résultats déjà existants de nouveaux aspects, témoignages, références et précisions tout en recourant à des documents inédits.</strong>\r\n\r\n<strong>   Le bilan est resté le même : à l\'image des révoltes précédentes, </strong><strong>la guerre d\'Algérie a souvent revêtu le caractère d\'un véritable <em>djihad</em>. Roger Vétillard analyse les identités et les stratégies respectives des principaux acteurs qui ont su à la fois imposer et cacher leur vision arabo-islamique de la future <em>Algérie algérienne</em> – tout en marginalisant, éliminant ou expulsant tous ceux qui s\'y opposaient. </strong>\r\n\r\n<strong>   Et surtout, il décrit le rôle important des <em>oulémas</em> dans </strong><strong>la préparation du soulèvement</strong><strong> ainsi que leur influence dans les rangs du F.L.N. durant le conflit tout comme dans le centre du pouvoir de la nouvelle Algérie musulmane.</strong>\r\n\r\n<strong>302 pages - une trentaine d\'illustrations - 24 €</strong>\r\n\r\n<span style=\"color: #ff0000;\"><strong><span style=\"color: #000000;\">À consulter aussi en pièce jointe (voir en bas de page) :</span> Wolf Albes - <em>La guerre d\'Algérie vue par six anciens combattants allemands de la Légion étrangère</em></strong></span>', 24, '9783932711688', 1),
(76, 1, 42, 'Café maure. Algérie 1934. Roman colonial', '<span style=\"font-size: 14pt;\"><strong><em>Café maure</em>, l\'avertissement resté lettre morte</strong></span>\r\n\r\n<strong>Entre 1929 et 1946, Charles Courtin, né à Blida en 1884, a publié six romans coloniaux, dits aussi <em>algérianistes</em></strong><strong>, dont <em>Café maure</em> (1939). </strong>\r\n\r\n<strong> </strong><strong>Fort de ses 30 ans d\'expérience comme administrateur des communes mixtes dans le Sud-Est algérien, Courtin connaît parfaitement la mentalité et les aspirations de la population musulmane tout comme celles de ses compatriotes pieds-noirs et métropolitains qu\'il nous décrit avec une précision et une objectivité impressionnantes.</strong>\r\n\r\n<strong> </strong><strong>Son bilan de la situation politique en Algérie dans les années 30, est alarmant : dans <em>Café maure</em>, le lecteur se retrouve face aux affrontements des différents mouvements religieux et nationalistes musulmans à Alger. Et tous les éléments sont déjà réunis qui mèneront inexorablement à l\'insurrection de mai 1945, dans le Nord-Constantinois, et celle du 1<sup>er</sup> novembre 1954. </strong>\r\n\r\n<strong>Pourquoi cet avertissement foudroyant de Charles Courtin n\'a-t-il pas été entendu ?</strong>\r\n\r\n<strong> </strong><strong>Si nous entrons bien dans un monde romanesque, il faut souligner que l\'auteur se base sur ses propres expériences et que plusieurs de ses protagonistes renvoient à des acteurs politiques de l\'époque très réels</strong><strong>…</strong>\r\n\r\n<strong>Avec l\'avant-propos au roman <em>Du sang sur la dune </em>(1942) de Charles Courtin</strong>\r\n\r\n<strong> Notes et commentaires de Wolf Albes</strong>\r\n\r\n<strong>22 €</strong>', 22, '9783932711640', 1),
(77, 1, 42, 'La brousse qui mangea l\'homme. Algérie 1914. Roman colonial', '<strong><span style=\"font-size: 14pt;\">Charles Courtin, romancier algérianiste</span> </strong>\r\n\r\n<strong>Séduit par le panégyrique de l\'Algérie, Prosper Duroux, \"paysan médio­cre et borné\", quitte sa Provence natale en 1914 pour s\'installer avec sa mère dans une ferme près de Raspail, dans l\'austérité des hauts plateaux. Là vit la tribu berbère des Ouled Yahia, des Chaouïas, chassés jadis de leurs pâturages du sud par d\'autres tribus et qui ont occupé à leur tour \"ce désert à perte de vue\" aux confins algéro-tunisiens. </strong>\r\n\r\n<strong>Ils </strong><strong>s\'acharnent par tous les moyens à chasser les colons, ces nouveaux</strong><strong> intrus \"infidè­les\", hors de la Terre d\'Islam, aidés par leur alliée : la brousse, cette \"mangeuse d\'hommes\".</strong>\r\n\r\n<strong>Avec une précision à couper le souffle, Charles Courtin, né à Blida en</strong><strong> 1884 et fort de sa longue expérience d\'administrateur, nous peint dans <em>La brousse qui mangea l\'homme</em> le microcos­me complexe de cette \"Comédie coloniale\" balzacienne qui tourne vite à la tragédie. </strong>\r\n\r\n<strong>Ce premier roman algérianiste de Courtin est bien plus \"vrai\" que n\'importe quelle analyse historique ou sociologique – sans pour autant perdre son impressionnante valeur esthétique. Sa principale qualité est néanmoins d\'exposer et d\'analyser avec justesse et objectivité les mentalités respectives de tous les protagonistes. </strong>\r\n\r\n<strong>Avec l\'avant-propos du roman <em>Du sang sur la dune </em>(1942) de Charles Courtin</strong>\r\n\r\n<strong>Notes et commentaires de Wolf Albes</strong>\r\n\r\n<strong>Collection <em>France-Algérie</em> 54</strong>\r\n\r\n<strong>Prix : 22 €</strong>', 22, '9783932711695', 1),
(78, 1, 42, 'Au pays de la paresse. Algérie 1930. Roman colonial', '<span class=\"readonlyText multiple\"><span style=\"font-size: 14pt;\"><strong>L\'univers des nomades dans les Hauts-Plateaux algériens</strong></span>\r\nLe nomade Amor tombe amoureux de la belle Nedjma. Pour pouvoir payer la dot, il est obligé de travailler dans la mine de fer de l\'Ouenza (entre Souk-Ahras et Tébessa). Mais le père de Nedjma lui préfère son rival Seghir qui lui offre des terres fertiles qu\'il convoite depuis toujours.\r\nAmor décide alors d\'enlever Nedjma et de se réfugier en Tunisie…\r\nC\'est à nouveau avec une justesse et une lucidité incomparables que Charles Courtin, fort de ses longues expériences d\'administrateur du bled, dépeint l\'univers des nomades dans les Haut-Plateaux algériens.\r\nCes nomades \"au pays de la paresse\", devenus sédentaires sous la colonisation française, se transforment à nouveau en \"nomades modernes\" en quittant leurs douars pour aller travailler chez les \"infidèles\" – à la mine de l\'Ouenza ou en traversant la Méditerranée.\r\nEt c\'est grâce à cet argent et ce lent changement de mentalité que les musulmans semblent préparer leur revanche :\r\n\r\n\"Les Musulmans rachetaient leurs terres aux Chrétiens. Leurs salaires, l\'argent dont les roumis rétribuaient leur fatigue, ils les affectaient à cette reprise sournoise du sol. La terre des ancêtres, ils la reprenaient, lambeau par lambeau, péniblement. Ce travail qu\'ils méprisaient, c\'était une arme que les roumis leur offraient pour les vaincre, une arme redoutable, qui amènerait peut-être la défaite de leur race, parce qu\'ils n\'en sentiraient la menace que trop tard.\"</span>\r\n\r\nNotes, commentaires et analyses de Wolf Albes.\r\n\r\nAvec une documentation sur la mine de l\'Ouenza.\r\n\r\nRéédition de l\'édition originale de 1942 (Librairie Alphonse Lemerre, Paris) : <em>Au Pays de la Paresse</em>\r\n\r\nCollection France-Algérie 57\r\n\r\n22 €', 22, '978-3-932711-74-9', 1),
(79, 1, 42, 'Du Sang sur la dune. Algérie 1920. Roman colonial', '<span class=\"readonlyText multiple\"><span style=\"font-size: 14pt;\"><strong>La condition de la femme dans la société musulmane</strong></span>\r\n\"Dîb revoyait le corps onduleux que renflait délicieusement sur la poitrine l\'ambre des seins. Subite, une flamme de désir l\'embrasa. Le baiser de Mériem, il en sentait tout à coup sur ses lèvres le goût poivré. Lorsqu\'elle liait ses bras autour de sa taille, il était prêt à défaillir, tellement il attendait avec impatience l\'extase amoureuse.\r\nC\'était elle qui lui enseignait le plaisir. Elle le traitait en adolescent qui n\'a pas encore terminé son initiation. Alors elle était grave comme une prêtresse de la volupté. L\'étreinte devenait une sorte de rite dont elle ne livrait que peu à peu le secret. Elle apportait une sombre ardeur à ce jeu qui la conduisait lentement à la pâmoison.\r\nÀ l\'aube, il se réveillait incapable de faire un geste, plus las que d\'avoir cheminé toute une journée au soleil, dans l\'immense monotonie des dunes. Elle riait de le voir étendu sans force sur le lit. Sans doute goûtait-elle ainsi, confusément, une revanche de femelle d\'Islam, heureuse de dominer le mâle à son tour.\"\r\nC\'est par cette liaison entre le chamelier Dîb et Mériem, belle et prestigieuse danseuse de la tribu des Ouled-Naïl, que débute une véritable tragédie. L\'Agha Senouci, maître violent et cruel de Mériem, fera assassiner son rival. Pour venger son amant, Mériem séduira Si Otmane, fils du marabout des Ouled-Amor.\r\nIl y aura à nouveau \"du sang sur la dune\"…</span>\r\n\r\n&nbsp;\r\n\r\nNotes de Wolf Albes\r\n\r\nRéédition de l\'édition originale de 1942 (Éditions Baconnier Frères, Alger) : <em>Du sang… sur la dune…</em>\r\n\r\nCollection France-Algérie 56\r\n\r\n20 €', 20, '978-3-932711-73-2', 1),
(80, 1, 43, 'Der Monumentalmaler Johann Jakob Zeiller. 1708-1783. Vorwort von Andreas Gamerith', '<span class=\"readonlyText multiple\"><strong>Johann Jakob Zeiller</strong>, bedeutendster Spross der Reuttener Malerfamilie Zeiller, hatte an der Entwicklung des spätbarocken Freskos maßgeblichen Anteil.\r\nSein grandiosestes Werk ist sicherlich das Ettaler Kuppelfresko. Ganze sieben Jahre lang arbeitete er in Ottobeuren. Mit seinen <em>al fresco</em> umgesetzten Ideen erwies sich dieser Virtuose der Barockmalerei als kongenialer Interpret der gebauten Architektur.\r\nJosef Mair, bekannt durch seine exzellenten Studien zu Balthasar Riepp (2003) und Paul Zeiller (2008), hat nun auch Johann Jakob Zeillers Werk übersichtlich skizziert und – auch für den Laien verständlich – erläutert</span>\r\n\r\n60 Seiten mit über 60 fast ausschließlich farbigen Abbildungen.', 14, '978-3-932711-72-5', 1),
(81, 1, 42, 'Sept Nuits sur un cadavre. Algérie 1930. Roman colonial', '<span style=\"font-size: 14pt;\"><strong>Au pays de la <em>rekba</em><em> : </em><em>«</em><em> œil pour œil, dent pour dent </em><em>»</em></strong></span>\r\n\r\nChebrek, Kabyle du massif du Djurdjura, donne au tueur à gages Yataghène la mission d\'assassiner son beau-père Nour Eddine qui l\'a blessé doublement dans son honneur : il lui a repris et séquestré Tozeur, sa femme, parce qu\'il ne lui aurait pas encore payé la totalité de la dot, et il l\'a même giflé devant des femmes.\r\n\r\nFurieuse, Kamir, la mère de Nour Eddine, appelle son petit-fils Amokrane à venger son père selon la tradition de la <em>rekba</em>. Mais Amokrane refuse de tuer Chebrek. Comme les Kabyles du Djurdjura prétendent que si un assassin peut enjamber sept fois le corps de sa victime, dans les sept jours qui suivent le crime, il met ainsi la famille du mort dans l\'impossibilité de le venger, Kamir fait immédiatement enlever le cadavre de son fils. Elle l\'enterre sous sa tente et le garde pendant sept jours pour ensuite poursuivre sa vengeance.\r\n\r\nAmokrane, révolté par le comportement de sa sœur Tozeur qui trahit son clan en rejoignant clandestinement son mari Chebrek, finit par engager à son tour Yataghène pour tuer son beau-frère.\r\n\r\nTozeur va-t-elle alors se retourner contre son propre frère ?\r\n\r\n<em>«</em><em> Tozeur était prête à fléchir les genoux devant la pyramide pelée du Lella Khedidja, ce point culminant du massif du Djurdjura, qui devenait une divinité monstrueuse. Il semblait qu\'elle personnifiait la </em>rekba<em>, l\'atroce loi de la montagne berbère. C\'était elle qui exigeait du sang, toujours du sang, le sang des pères et le sang des fils, comme si elle s\'était donné pour tâche d\'en vider les veines de la race jusqu\'à la dernière goutte. </em><em>»</em>\r\n\r\nISBN 9783932711756\r\n\r\nNotes de Wolf Albes\r\n\r\nRéédition de l\'édition originale d\'octobre 1945\r\n(Éditions Française de Librai­rie, Alger)\r\n\r\nCollection <em>France-Algérie</em> 58\r\n19 €', 19, '9783932711756', 1),
(82, 1, 44, 'Le Troisième Rubicon.  Forces françaises libres. 13 mai 1958. OAS Oran. Récit historique romancé', '<span style=\"font-size: 14pt;\"><strong><em>Le Troisième Rubicon</em> : de la Résistance à l\'OAS</strong></span>\r\n\r\nCet impressionnant récit, Daniel Pouilly l\'a consacré à l\'histoire de son père qui a franchi le Rubicon à trois reprises :\r\n<ul>\r\n 	<li>d\'abord en suivant l\'appel de De Gaulle pour se battre dans les <em>Forces françaises libres </em>du général Leclerc jusqu\'à la Libération ;</li>\r\n 	<li>ensuite, lors de l\'insurrection de mai 1958 en Algérie, pour se joindre à l\'appel au \"plus illustre des Français\", censé mettre fin au terroris­me totalitaire du FLN ;</li>\r\n 	<li>enfin, face à la trahison de De Gaulle, pour participer au combat de l\'OAS, seul moyen de défendre les siens contre la mort et l\'exil.</li>\r\n</ul>\r\n&nbsp;\r\n\r\n<strong><span style=\"font-size: 14pt;\">Contre la falsification de l\'histoire</span></strong>\r\n\r\n<em>Reparler de cette période, cela faisait mal à mon père. L\'amertume de</em> <em>la défaite, celle de l\'Algérie perdue, mais surtout celle de la falsi­?­cation</em><em> de l\'histoire, honteuse, abjecte, déshonorante : les menson­ges et la calomnie qui faisaient passer les Pieds-Noirs pour des fascistes et des </em><em>assassins, l\'armée française pour une bande de tortionnaires, la coloni­sa­tion pour une œuvre destructrice, les terroristes du FLN et leurs soutiens français pour des parangons de vertu et d\'humanisme.</em>\r\n\r\n&nbsp;\r\n\r\n<strong><span style=\"font-size: 14pt;\">Daniel Pouilly : <em>\"Voilà ce que c\'était, l\'OAS…\"</em></span></strong>\r\n\r\n<em>\"</em><em>À nous de prendre la plume pour évoquer le</em><em> drame de l’abandon de l’Algérie, dû à un pouvoir sans scrupules, pressé d’en finir à n’im­porte quel prix, tout en trahissant ses ressortissants et en les livrant à ses ennemis totalitaires et islamistes. </em>\r\n\r\n<em>Je</em> <em>voudrais faire comprendre</em><em> nos souffrances et notre </em><em>angoisse face au terrorisme du FLN, mais aussi notre détermination </em><em>à nous défendre jusqu’au bout, puisque personne ne l\'a fait pour nous</em><em>. </em>\r\n\r\n<em>Je voudrais que ceux qui lisent ce récit n’oublient jamais ceci : </em><em>un peuple menacé d’exil et de mort, des hommes et des femmes sur qui planent l’égorgement, le viol, l\'enlèvement et qui se rassemblent pour se défendre, voilà ce que c’était, l’OAS.\"</em>\r\n\r\nRécit historique romancé\r\n\r\nAvant-propos de Wolf Albes\r\n\r\nCollection <em>France-Algérie</em> 59\r\nISBN 9783932711763\r\n\r\n25 €\r\n\r\n<span style=\"color: #ff0000;\"><strong>Paru le 19 novembre 2020.\r\n</strong></span>', 25, '9783932711763', 1),
(83, 7, 45, 'Tradition et révolution. L\'armée prussienne en 1870', '<strong>En 1870, la Prusse écrase dans un véritable <em>Blitzkrieg</em> l’empire napoléonien. Elle réussit l’unité nationale en 1871 et devient un acteur majeur du continent européen.</strong>\r\n\r\n<strong>L’instrument de ce succès, c’est son armée, terrible <em>glaive de Siegfried</em>, forgé par trois génies de l’organisation : Otto von Bismarck, Albrecht von Roon et Helmuth von Moltke.</strong>\r\n\r\n<strong>Comment l’<em>Année terrible </em>et ses événements majeurs – Sedan, le siège de Paris, la proclamation du Deuxième Reich dans la galerie des Glaces de Versailles, le traité de Frankfurt, l’annexion de l’Alsace-Moselle – ont-ils pu s’enchaîner aussi rapidement ?</strong>\r\n\r\n<strong>Comment la Prusse parvient-elle à lever la plus formidable armée terrestre de son époque, en réunissant quelques petites armées jadis rivales et les articuler en corps d’armées loyaux, souples, manœuvriers et redoutablement efficaces ?</strong>\r\n\r\n<strong>Comment inventent-ils la figure archétypale – la <em>Gestalt</em> – de l’officier prussien, réincarnation des chevaliers teutoniques ?</strong>\r\n\r\n<strong>Comprendre l’armée prussienne, ses mécanismes, son ordre de bataille et sa doctrine d’emploi en 1870 donne aussi les clés des deux guerres mondiales à venir...</strong>', 19, '9783932711817', 1),
(84, 1, 30, 'Death of a Dream. Algeria 1958. A True Novel', '<strong>A Dream for a New Algeria</strong>\r\n\r\nOn the night of 8 April 1958, Félix Vallat, mayor of Thiersville (French Algeria), and his wife Madeleine, a schoolteacher, were savagely killed by a commando of the FLN (<em>National Liberation Front</em>) on their way home to their farm. Their three sons miraculously survived.\r\n\r\nThat night the target was not the agricultural engineer, the former Royal Air Force pilot, or the exemplary leader.\r\n\r\nNo, it was simply the true preacher of a harmonious and equitable Franco-Muslim cohabitation who was upsetting the extremist Algerian nationalists and who had to be eliminated with his entire family.\r\n\r\nWith them died a dream for a new Algeria, an independent and fraternal, multi-ethnic and tolerant Algeria with close ties to France.\r\n\r\nThis was the Algeria of which Albert Camus also dreamed.\r\n\r\n&nbsp;\r\n\r\nMaïa Alonso has given us a true novel about the life of the Vallat family:\r\n\r\n<em>\"I want all of the participants in this drama to have their voices heard – even the voice of the horrible assassin who commanded their deaths, one of the Muslims who were Félix Vallat’s close friends. While the FLN’s terror tactics are denounced, the vengea­nce that certain disgusted and desperate people sought in return is also pointed out.\"</em>\r\n\r\nThis novel treats a current hot topic: will peaceful cohabitation in Islamic countries remain just a dream?\r\n\r\n<strong>This book received the 2017 Prize from the <em>Foundation for the Memory of the Algerian War and fighting in Morocco and Tunisia</em></strong> (<em>Fondation pour la Mémoire de la Guerre d’Algérie, des combats du Maroc et de Tunisie</em>).\r\n\r\nTranslated by <strong>Amy Hubbell</strong>, <strong>Jorien van Beukering</strong>, <strong>Jenny Barnett</strong>, <strong>Janna Guy</strong>, and <strong>Jorgia Brown</strong>.\r\n\r\nSome portions were originally drafted by students in French to English Translation at the University of Queensland (Australia).\r\n\r\n&nbsp;', 22, '9783932711770', 1),
(85, 2, 46, 'Mythos Légion étrangère. Mai avere paura. Erinnerungen eines italienischen Legionärs', '1995 erhält Danilo Pagliaro das begehrte <em>Képi blanc</em> und kommt unter seinem neuen Namen Pedro Perrini zum 1. Kavallerieregiment der Fremdenlegion (1<sup>er</sup> REC) in Orange. Bald bricht er zu zahlreichen Missionen auf dem Balkan und vor allem in Schwarzafrika auf.\r\n\r\nPagliaros Buch avancierte in Italien rasch zum Bestseller. Es ist ihm im Rückblick auf 20 Jahre Dienstzeit gelungen, ein authentisches, sehr emotionales Bild der Legion abseits von dümm­lichen Vorurteilen oder verqueren Gewalt-Fantasien zu zeichnen.\r\n\r\nUrkomische und tief bewegende Anekdoten tauchen den Leser immer wieder in ein Wechselbad der Gefühle.\r\n\r\n\"Ich werde oft gefragt, ob ich unter Traumata leide. In der Tat habe ich Dinge von unvorstellbarer Brutalität gesehen, über die jedoch wahre Legionäre, echte Soldaten, niemals sprechen und die ich bewusst in diesem Buch ausgeklammert habe.\r\nSolche Dinge erzählt man nicht. Das gehört sich nicht.\r\nNach dem ersten Schock besinnt man sich dann auch schnell, denn gerade um dieser Barbarei ein Ende zu bereiten, waren meine Kameraden und ich ja doch losgeschickt worden.\r\nNiemals werde ich die dankbaren Blicke der Männer, Frauen und Kinder vergessen, als wir im Hexenkessel von Bangui 1996 die Viertel Straße um Straße durchkämmten, sie aus ihren Verstecken holten und vor den Rebellen in Sicherheit brachten.\r\nIch glaube, es waren diese Blicke, das Bewusstsein, dass wir Legionäre eine so wichtige Mission erfüllten, die mich letztlich vor Traumata bewahrt haben.\"\r\n\r\n<span style=\"color: #ff0000;\"><strong>Erscheint am 4. Januar 2022.</strong></span>', 20, '9783932711787', 1),
(86, 1, 47, 'Un combat tranquille. Une fille de Harki se souvient. Récit autobiographique', '<span style=\"font-size: 18pt;\"><strong>Le combat tranquille d\'une fille de Harki</strong></span>\r\n\r\n<strong>Dans ce récit autobiographique de Hafida Chabi, ancien membre de section du CESE (Conseil économique, social et environnemental), le lecteur suivra le regard d\'une fille de Harki, qui, à l\'âge de cinq ans, sera déracinée et projetée avec toute sa famille dans un pays inconnu : la France métropolitaine.</strong>\r\n\r\n<em><strong> </strong><strong>\"J\'ai ramassé toutes les bribes de mes souvenirs pour reconstruire comme dans un puzzle ma propre vie et celle de mes parents :\r\n</strong></em><em><strong>Youcef, mon père, qui s\'est engagé comme Harki dans l\'armée française.\r\n</strong></em><em><strong>Dabhia, ma mère, qui s\'est occupée pendant toute sa vie de son mari et de ses treize enfants.\r\n</strong></em><em><strong>J\'ai écrit ce livre pour laisser des traces, pour que toutes ces souffrances ne disparaissent jamais.\r\n</strong></em><em><strong>Pourtant, le combat que j\'ai dû mener tout au long de ma vie n\'a jamais été violent. Il est à l\'image de celui de mes parents : humble et mesuré.\r\n</strong></em><em><strong>Un combat tranquille.\"</strong></em>\r\n\r\n<em><strong> </strong></em><em><strong>\"Mes parents sont arrivés en France dans un dénuement total. À la détresse matérielle s’est ajoutée une profonde détresse morale, car ils ont mal vécu l’absence de reconnaissance de leur sacrifice pour la France.\r\n</strong></em><em><strong>Cependant, ils n’ont eu de cesse de nous transmettre les valeurs fondamentales de la République parce qu’ils souhaitaient avant tout que leurs enfants se fondent dans la société française.\" (Hafida Chabi)</strong></em>\r\n\r\nCollection France-Algérie 60\r\n\r\nISBN 9783932711794\r\n\r\nPrix : 16 €', 16, '9783932711794', 1),
(87, 1, 48, 'Los caracoles. L\'épopée d\'une famille espagnole à travers l\'Algérie et le Maroc', '<strong>Oran – Saïda – Sidi-Bel-Abbès – Oujda – Casablanca – Port-Lyautey… </strong>\r\n\r\nVoici la saga des Riquelme, une famille espagnole qui, à la fin du 19<sup>e</sup> siècle, par­tit en Algérie et au Maroc, où ils firent sou­che sur plusieurs générations.\r\n\r\nIls font partie des <em>caracoles</em> (escargots), surnom donné aux émigrants espagnols, car ils portaient leur mai­son sur leur dos.\r\n\r\n&nbsp;\r\n\r\n<strong>Los caracoles – \"les escargots\"</strong>\r\n\r\n\"Les Espagnols débarquaient en hordes compactes dans la province d\'Oran, accompagnés de leurs femmes et d\'une grouillante progéniture.\r\n\r\nIls s\'en allaient ainsi, basanés et déguenillés, accablés sous le fardeau de la misère, vers l\'inconnu, à la recherche du croûton de pain.\"  (Jean-Jacques Jordi, <em>Espagnol en Oranie</em>)\r\n\r\n&nbsp;\r\n\r\nCollection France-Algérie 61\r\n\r\n140 pages\r\n\r\n19 €\r\n\r\nISBN  9783932711831\r\n\r\n&nbsp;\r\n\r\n&nbsp;', 19, '9783932711831', 1),
(88, 11, 30, 'À demain dans les étoiles. Carnets vagabonds', '<span class=\"readonlyText multiple\">Ce recueil d’écrits au fil des ans, retrouvés, choisis, rassemblés, va vous permettre – si vous savez lire entre les lignes – de découvrir l’écrivain à fleur de peau qui se cache derrière l’apparente légèreté de ses vagabondages ou la gravité plus marquée de ses amours mortes.\r\nLisez sans retenue et consommez sans modération.\r\nC’est après, quand vous aurez refermé le livre, que vous comprendrez ce qui a guidé Maïa Alonso dans le choix de ce qu’elle vous propose.\r\nCar il y a un fil conducteur.\r\n<em>Danièle Strazza</em></span>\r\n\r\nMaïa Alonso est née en Algérie.\r\nLa petite fille heureuse qui courait après le vent dans l’éblouissante lumière de son bled a fait place à une adolescente solitaire, révoltée par la déchirure de l\'exil.\r\nL\'écriture sera son refuge.\r\nEncouragée par l\'écrivain Gil Jouanard qui signe la pré-face de son premier livre, elle se tourne assez tard vers l\'édition, en 2013.\r\nElle a publié depuis sept romans.\r\nCorrespondante de <em>La Dépêche du Midi</em>, elle allie ses deux passions : l\'écriture et les rencontres humaines.', 15, '978-3-932711-84-8', 1),
(89, 1, 37, 'Orientalisme et Lauréats de la Villa Abd-el-Tif Catalogue de l\'exposition du 18 au 28 avril 2024. Espace Saint-Michel à Condom', '<span style=\"font-size: 14pt;\"><strong>Une exposition hors du commun dans un lieu magique</strong></span>\r\nC’est en avril 2024 que Roger et Michèle Vétillard, Jean-Marcel Lainé et l’Amicale Marcel Lizon de Quint-Fonsegrives ainsi que l\'équipe du Cercle algérianiste du Gers organisaient une exposition magnifique d’une centaine d’œuvres orientalistes dans le cadre de l\'ancienne église néo-gothique Saint-Michel à Condom.\r\nDurant une dizaine de jours, près d\'un millier de visiteurs ont ainsi pu admirer les œuvres de 57 artistes orientalistes, tous fascinés par l’Algérie et souvent pensionnaires de la Villa Abd-el-Tif d’Alger.\r\n<span style=\"font-size: 14pt;\"><strong>Un hommage à Guy Forzy</strong></span>\r\nCette exposition était placée sous le signe d’un hommage à Guy Forzy, ancien délégué interministériel aux rapatriés et peintre amateur. Son tableau \"La Villa Abd-el-Tif\" figure sur la première de couverture de ce catalogue qui a été réalisé afin de faire revivre et conserver cette exposition inoubliable.\r\n<strong><span style=\"font-size: 14pt;\">Un retour doux-amer en Algérie…</span></strong>\r\nSi, à travers ces peintures, les visiteurs métropolitains découvraient un monde exotique inconnu, les Français d\'Algérie, eux, replongeaient dans cet univers oriental qui avait été jadis le leur.\r\nTout comme leurs parents, grands-parents et souvent même arrière-grands-parents, ils y étaient nés. Ils avaient passé leur enfance et leur jeunesse dans ce décor fascinant, dont ils ont été privés si brutalement.\r\nPour beaucoup de visiteurs \"pieds-noirs\", cette exposition fut comme un retour doux-amer dans une Algérie heureuse puisqu\'on leur a retiré \"le droit des hommes à ne pas être chassés de leurs souvenirs d\'enfance\" (Jean Brune).\r\n\r\nISBN : 9783932711855\r\n\r\n82 pages ; grand format (29 cm x 21 cm) ; 100 tableaux en couleur\r\n\r\n<span style=\"font-size: 14pt;\"><strong>Table des matières :</strong></span>\r\n\r\n<strong>Ce qu\'ils en pensent…</strong>\r\n\r\nMarie-Claude Montané-Séailles : <em>Les couleurs chaudes de l\'Algérie du siècle passé</em> ..................................................................................  7\r\n\r\nJean-François Rousse : <em>Une exposition des plus remarquables</em> .......................................  7\r\n\r\nSuzy Simon-Nicaise : <em>Un voyage émotionnel</em> ...................................................................  7\r\n\r\nRobert Scheddel : <em>Un événement unique dans notre région</em> ...................................................  8\r\n\r\nMarie-Paule Garcia : <em>L\'Afrique du Nord des Orientalistes et des Abd-el-Tif</em> ............  8\r\n\r\nMichèle et Roger Vétillard : <em>Richesse et vitalité de l’activité artistique en Algérie</em>. 8\r\n\r\nWolf Albes : <em>Le mot de l\'éditeur</em> .................  9\r\n\r\nMichèle Vétillard : <em>Les peintres orientalistes en Algérie et la Villa Abd-el-Tif</em>...................................................................................... 10\r\n\r\n<strong>Les artistes et leurs œuvres</strong> (tableau) ...  11\r\n\r\n<strong>Les artistes</strong> [notices biographiques]... 12\r\n\r\n<strong>Liste des collectionneurs qui ont contribué à l’exposition</strong> ..............................  22\r\n\r\n<strong>Les œuvres</strong> [classées par auteur - ordre alphabétique] ...............................................................  23\r\n\r\n&nbsp;', 23, '9783932711855', 1);
INSERT INTO `publikationen` (`pub_id`, `kat_id`, `aut_id`, `titel`, `text`, `preis`, `isbn`, `available`) VALUES
(90, 1, 2, 'Les Harkis. Drame ou tragédie ? 1955-2025 : un premier bilan', '<strong>Hafida Chabi et Wolf Albes présentent <em>Les Harkis. Drame ou tragédie ?</em></strong>\r\n\r\n<span style=\"font-size: 14pt;\"><strong>Maurice Allais : « Serions-nous des criminels ? »</strong></span>\r\n\r\nL\'abandon, l\'exode, le massacre des harkis, auraient-ils pu être évités comme dans un drame, où la fin est toujours incertaine ? Ou étaient-ils inévitables à cause de la situation coloniale, comme dans une tragédie antique, où, dès le début, le sort est inéluctable : alea jacta est ?\r\n\r\n<strong>« Serions-nous des criminels ? » La presse métropolitaine en 1962</strong>\r\nCette première partie avec l\'analyse des périodiques \"Libération\", \"L\'Express\", \"France Observateur\" et \"Les Temps modernes\" d\'un côté ainsi que \"Le Monde\", \"Le Figaro\", \"Paris Match\", \"L\'Aurore\" et \"Combat\", mais aussi \"La Nation française\" et \"L\'Esprit public\" de l\'autre, est pleine de surprises.\r\nComment la presse métropolitaine a-t-elle informé ses lecteurs sur les harkis ? S\'est-elle engagée pour eux ? Ou a-t-elle passé sous silence tout ce qui les concernait – sachant que les journalistes étaient parfaitement au courant de ce qui se passait ? Seraient-ils donc aussi responsables de leur malheur, un cas de non-assistance à personne en danger ?\r\nOu, pour citer Maurice Allais, prix Nobel 1988 et fervent défenseur des harkis dans \"Combat\" : « Serions-nous des criminels ? »\r\n\r\n<strong>Une centaine de notes de lecture</strong>\r\nDans la deuxième partie, le lecteur trouvera une centaine de notes de lecture de récits, de romans, de témoignages, d\'analyses, mais aussi de BD, de films et de pièces de théâtre qui constituent un premier bilan dans ce domaine qui – bien sûr – ne peut pas être exhaustif.\r\n\r\n<strong>Le « combat tranquille » continue</strong>\r\nDans la dernière partie, dans plusieurs entretiens, Hafida Chabi et Wolf Albes, tout en complétant le témoignage d\'« Un combat tranquille » (2022), essaient d\'ouvrir de nouveaux horizons pour mieux comprendre et transmettre l\'histoire des harkis telle qu\'elle se reflète dans les notes de lecture.\r\n\r\nCollection France-Algérie 61\r\n\r\n446 pages et 120 illustrations\r\n\r\n27 €', 27, '    978-3-932711-87-9', 1);
